-- ============================================================
-- AULA · 0012 — Currículo real NEM Fase 5 (5° y 6°)
-- Fuente: Mapa Curricular Fase 5 (Programa Sintético).
-- Reemplaza el set de muestra. Enriquece con campo formativo + PDA.
-- ============================================================

alter table public.curriculum_contents add column if not exists campo text;
alter table public.curriculum_contents add column if not exists detail text;

-- Limpia el set de muestra (5° y 6°) y su cobertura asociada
delete from public.curriculum_contents where grade in ('5','6');

insert into public.curriculum_contents (grade, subject, campo, content, detail, position) values
  ('5','Español','Lenguajes','Narración de sucesos autobiográficos.','• Lee textos autobiográficos y reflexiona sobre las razones por las que suelen estar narrados en primera persona del singular.
• Determina los sucesos autobiográficos que desea narrar y los organiza lógicamente, resaltando los aspectos más significativos.
• Escribe la narración de los hechos autobiográficos, haciendo uso de comas, puntos y seguido, puntos y aparte y dos puntos, para dar claridad y orden a las ideas.
• Describe personas, lugares y hechos a través del uso de reiteraciones, frases adjetivas, símiles e imágenes, y mantiene la referencia a los mismos en toda la narración por medio de pronombres y sinónimos.
• Hace y recibe sugerencias sobre aspectos de mejora, y comparte con la comunidad educativa las versiones finales.',1),
  ('5','Español','Lenguajes','Comprensión y producción de textos explicativos.','• Lee distintos tipos de textos explicativos y reflexiona sobre sus características y funciones.
• Expone las diferencias entre una descripción y una explicación, y entre un texto descriptivo y uno explicativo.
• Recupera información de distintas fuentes, como artículos de divulgación, libros de texto, reportes de investigación, para producir un texto explicativo sobre temas diversos y con propósitos particulares.
• Establece relaciones causales y emplea expresiones como en consecuencia, por lo tanto, debido a, a causa de, porque, por consiguiente.
• Distingue sus propias palabras de la paráfrasis y citas textuales, y registra la información bibliográfica de las fuentes consultadas: autor, título, editorial, lugar y fecha de publicación, páginas consultadas, etcétera.',2),
  ('5','Español','Lenguajes','Participación en debates sobre temas de interés común.','• Reconoce que hay temas donde las opiniones se dividen, y es necesario sustentar las propias.
• Conoce la función y organización de un debate.
• Investiga y toma notas de las ideas centrales y otros datos significativos con relación al tema del debate, con la intención de construir sus argumentos.
• Identifica la función de los nexos de subordinación en textos argumentativos.
• Hace su presentación, opina sobre lo que dicen otros y otras participantes y reconoce que es posible cambiar de opinión, a partir de las opiniones argumentadas de las demás personas.',3),
  ('5','Español','Lenguajes','Comprensión y producción de textos argumentativos.','• Lee textos sobre temas polémicos, y distingue las opiniones de los datos y hechos concretos.
• Compara distintas formas de construir y expresar argumentos, siempre en un marco de respeto.
• Expresa sus opiniones oralmente, basado en argumentos, sobre textos que incluyen temas polémicos.',4),
  ('5','Español','Lenguajes','Comprensión y producción de textos informativos, para ampliar sus conocimientos sobre temas de interés tanto colectivo como individual.','• Selecciona y lee textos informativos sobre temas de su interés.
• Formula preguntas para guiar la búsqueda de información específica, para lo cual usa los signos de interrogación.
• Reconoce el tema central de los textos leídos.
• Escribe textos informativos, empleando signos de puntuación: coma, dos puntos, punto y seguido, y punto y aparte, para organizar las ideas dentro de los párrafos.',5),
  ('5','Español','Lenguajes','Comprensión y producción de textos discontinuos, para organizar y presentar información.','• Reconoce, mediante el análisis, las características y funciones de los textos discontinuos, en particular de tablas de doble entrada, líneas del tiempo y cuadros cronológicos.
• Reflexiona sobre la utilidad de los textos discontinuos para organizar y presentar información.
• Selecciona información para organizarla y presentarla por medio de textos discontinuos.
• Produce textos discontinuos, considerando al destinatario y tomando en cuenta aspectos gráficos como el tamaño de la letra empleada, a fin de garantizar su legibilidad.',6),
  ('5','Artes','Lenguajes','Elaboración e intercambio de reseñas de diversos textos y/o audiovisuales.','• Reconoce las características y función de las reseñas.
• Describe un texto leído y construye una opinión acerca del mismo, explicando su parecer.
• Usa expresiones como creo que, en mi opinión, pienso que, de acuerdo con, desde mi punto de vista, considero que, para organizar y compartir su opinión.
• Registra datos de identificación del texto: título, autor, editorial y lugar y fecha de publicación, número de páginas.
• Revisa y corrige reiteraciones innecesarias en la escritura de la reseña: errores de concordancia y de ortografía en general.',7),
  ('5','Español','Lenguajes','Comparación y producción de documentos que regulan la convivencia.','• Analiza varios reglamentos escolares, e identifica características como brevedad o concisión y uso de verbos y numerales.
• Comprende y explica la función de los reglamentos.
• Participa en la elaboración del reglamento del aula.
• Revisa y corrige errores de concordancia y ortografía en el texto.',8),
  ('5','Español','Lenguajes','Exposición sobre temas relacionados con el cuidado de la salud.','• Como presentador o presentadora
• -Recupera e integra información de diversas fuentes, gráficas, orales y/o escritas, para preparar su presentación.
• -Escribe palabras clave y/o notas breves para usarlas como guía y exponer de manera lógica y secuenciada, empleando un léxico formal.
• -Elabora cuadros sinópticos, esquemas, tablas de doble entrada u otros recursos gráficos, como material de apoyo para la exposición.
• -Conserva la atención de las espectadoras y los espectadores, resuelve dudas y hace comentarios acerca de lo que le plantean.
• Como audiencia
• -Mantiene la atención en lo que presenta la expositora o el expositor, toma notas sobre lo que le parece más relevante, le causa duda o quiere comentar, y pide y hace uso de la palabra para plantear preguntas, hacer comentarios o compartir su opinión.',9),
  ('5','Español','Lenguajes','Producción y envío de cartas personales.','• Lee distintas cartas personales reales y literarias.
• Reflexiona sobre las características y funciones de las cartas personales enviadas por correo postal y electrónico.
• Expresa sentimientos, ideas y experiencias por medio de cartas, pensando en destinatarias y destinatarios específicos.
• Reconoce palabras y expresiones que señalan tiempo y espacio en las cartas personales: allá, aquí, ahí, acá, hace tiempo.
• Envía las cartas que escribe a través del correo postal y/o electrónico.',10),
  ('5','Español','Lenguajes','Interpretación y producción de anuncios publicitarios de productos o servicios ofrecidos en la comunidad.','• Analiza anuncios publicitarios impresos y electrónicos, e identifica sus características y funciones.
• Reflexiona sobre los recursos empleados para persuadir a los consumidores, como las imágenes que utilizan y, en particular, las características del lenguaje escrito; por ejemplo, uso de adjetivos, rimas, juegos de palabras, metáforas y comparaciones, así como la brevedad.
• Identifica los productos y servicios ofrecidos en su comunidad que desea publicitar.
• Elabora anuncios publicitarios en los que emplea distintas estrategias textuales para persuadir a su público objetivo, cuidando la distribución gráfica; por ejemplo, el tamaño y colocación de texto e imagen, así como la claridad.
• Difunde con las personas de la comunidad los anuncios publicitarios elaborados.',11),
  ('5','Español','Lenguajes','Seguimiento crítico de noticias en diferentes medios de comunicación escrita.','• Expresa interés por una noticia particular y busca notas informativas relacionadas en distintos medios de comunicación escrita: periódicos, revistas, portales de internet.
• Da seguimiento a las noticias de su interés en diferentes medios de comunicación escrita.
• Analiza los elementos que componen las notas informativas sobre noticias de su interés en los diferentes medios de comunicación escrita: títulos, balazos, entradillas, tipografías, usos de espacios, puntuación, elementos gráficos, formas de referirse a las personas o lugares involucrados.
• Compara las diferencias y similitudes en las distintas formas de presentar las noticias de su interés.
• Comparte sus reflexiones sobre los hechos noticiosos de su interés y sobre la experiencia de darles seguimiento en diferentes medios de comunicación escrita.',12),
  ('5','Español','Lenguajes','Comprensión y producción de textos para gestionar servicios públicos.','• Explora distintos formularios para gestionar servicios públicos: los que brinda la escuela, la biblioteca o, en general, la comunidad.
• Reflexiona tanto sobre la utilidad de esta clase de documentos como sobre sus características y funciones.
• Llena diferentes formularios e identifica el tipo de información que incluyen y solicitan.
• Reconoce la utilidad de los formularios para gestionar servicios públicos.',13),
  ('5','Español','Lenguajes','Elaboración de un tríptico informativo sobre la prevención de algún problema colectivo.','• Recopila y analiza distintos trípticos informativos para conocer sus características y funciones.
• Determina, por medio del diálogo con sus compañeras y compañeros, algún problema colectivo que pueda prevenirse, relacionado con la salud, la violencia, el bienestar.
• Investiga en varias fuentes sobre el problema colectivo que quieren prevenir y, en común acuerdo con sus pares, integra la información más relevante en un texto breve que incluya nexos que ayuden a que las ideas se presenten de manera ordenada y coherente.
• Organiza la información textual y gráfica en un tríptico en el que se defina el problema que quieren prevenir y las razones para hacerlo, así como las medidas de prevención y las personas, fuentes o instituciones a las cuales es posible recurrir para profundizar en el asunto o buscar ayuda.
• Presenta y difunde el tríptico con la comunidad escolar.',14),
  ('5','Español','Lenguajes','Reconocimiento de la diversidad lingüística de México.','• Investiga en fuentes impresas y/o electrónicas sobre la diversidad lingüística en México y sobre la influencia de las lenguas originarias en el español en México.
• Averigua por medio de entrevistas con personas adultas mayores y la consulta de diccionarios, algunas palabras usuales en el español mexicano que provienen de lenguas originarias.
• Registra las palabras sobre las que averiguó, comprende su significado y, de ser posible, indaga en su historia. Comparte el resultado de su investigación.
• Reflexiona sobre la diversidad lingüística en México y valora su riqueza.',15),
  ('5','Artes','Lenguajes','Interpretación y valoración de manifestaciones culturales y artísticas de México y del mundo.','• Explora manifestaciones culturales y artísticas de diversos orígenes, e identifica sus elementos, para recrearlos mediante textos y otras producciones artísticas, que amplíen sus concepciones de ser y estar en el mundo.
• Relaciona el uso de textos, imágenes, colores, objetos, sonidos, silencios, aromas y movimientos, presentes en manifestaciones culturales y artísticas, con los que infiere su significado, a partir de intereses, perspectivas y creencias propias.
• Construye significados en lo individual y colectivo, a partir de la observación y comprensión de sonidos, gestos, formas, colores, texturas, objetos, aromas, movimientos, así como del contexto de creación de manifestaciones culturales y artísticas.',16),
  ('5','Artes','Lenguajes','Apropiación e intervención artística en el espacio comunitario.','• Plantea propuestas creativas de atención y/o solución, al identificar y socializar necesidades, intereses y problemas de la comunidad.
• Representa problemas detectadas en su comunidad, por medio de historietas, maquetas, improvisaciones teatrales, una secuencia dancística o una canción popular donde modifique su letra para compartir su perspectiva con otras personas.
• Planea e interviene un espacio de la escuela o la comunidad, utilizando objetos y materiales a su alcance, así como su cuerpo, sonidos y gestos.',17),
  ('5','Literatura','Lenguajes','Análisis de cuentos y poemas para su disfrute y comprensión.','• Lee y selecciona cuentos y poemas mexicanos a partir de sus intereses y gustos, y comparte los motivos de su elección.
• Analiza cuentos y poemas, y expresa oralmente sus interpretaciones de estos.
• Distingue las características tanto de cuentos como de poemas.
• Organiza y participa en un recital literario en el que lee en voz alta cuentos y poemas para la comunidad escolar.
• Crea poemas y cuentos en colectivo a partir de historias propias, familiares o populares.',18),
  ('5','Artes','Lenguajes','Combinación de elementos visuales, sonoros y corporales, en composiciones artísticas colectivas, para expresar rasgos de sus identidades personal y colectiva.','• Relaciona movimientos corporales con sonidos producidos con objetos del entorno, el cuerpo y/o la voz, en secuencias colectivas que narran una historia propia que les es significativa.
• Explora sonidos graves, agudos, rápidos, lentos, fuertes, débiles, largos, cortos, con pausas y acentos, para relacionarlos con la voz y características de un personaje, que crea a partir de objetos cotidianos y de sus rasgos de identidad personal.
• Recrea colectivamente una misma escena o paisaje de su entorno natural o social, con
• mientos corporales y sonidos, y posteriormente con objetos en una secuencia animada (stop motion) o una historieta.
• Construye propuestas artísticas de manera grupal, a partir del uso de formas, colores, texturas, sonidos, movimientos y gestos, que representen su identidad colectiva.',19),
  ('5','Artes','Lenguajes','Expresión, mediante el uso de los lenguajes artísticos, de experiencias estéticas que tienen lugar en la naturaleza.','• Comparte sensaciones, emociones, sentimientos e ideas, a partir del asombro generado por la interacción con la naturaleza y representa su experiencia en una producción artística.
• Reconoce formas, colores, texturas, sonidos y movimientos algunos componentes de la naturaleza y los recrea por medio de los lenguajes artísticos.',20),
  ('5','Artes','Lenguajes','Creación y representación de narrativas a partir de acontecimientos relevantes de la comunidad, empleando recursos literarios, visuales, corporales y sonoros.','• Combina secuencias de movimientos, gestos, formas, sonidos, colores y objetos, a partir de cuentos que lee o escucha.
• Desarrolla relatos escritos o crea narrativas corporales a partir del significado de su nombre y la historia familiar de cómo y por qué eligieron ese nombre.
• Narra y representa teatral o dancísticamente historias o situaciones cotidianas de su comunidad que sean trágicas, cómicas, románticas, etcétera.',21),
  ('5','Artes','Lenguajes','Combinación de la realidad y la ficción en elementos simbólicos de las manifestaciones culturales y artísticas, que dan identidad y sentido de pertenencia.','• Aprecia movimientos, gestos y formas que crean los objetos y los cuerpos en una manifestación cultural o artística, para reflexionar sobre aquello que simbolizan.
• Aprecia colores, sonidos y silencios en una manifestación cultural o artística de su interés, y los contrasta con el significado que representan.
• Combina intencionalmente secuencias de formas, colores, texturas, sonidos, silencios, movimientos, gestos y objetos, para recrear un fragmento de una manifestación cultural o artística con elementos simbólicos propios.',22),
  ('5','Artes','Lenguajes','Análisis y representación de guiones teatrales.','• Lee y analiza guiones teatrales de su elección, para reflexionar en colectivo sobre sus argumentos o tramas, las características de los personajes, así como los temas y conflictos que abordan.
• Realiza lecturas en voz alta de guiones teatrales y los representa en colectivo, mediante el empleo del cuerpo, procurando respetar los elementos que le permiten ser escenificados, tales como la presencia de acción, el conflicto, los diálogos, los personajes, las acotaciones y la tipografía empleada para distinguirlos.
• Crea personajes y escenografías para la historia de una obra de teatro infantil y la sonoriza para representarla ante la comunidad.',23),
  ('5','Literatura','Lenguajes','Lectura y análisis de mitos y leyendas, para su disfrute y valoración.','• Lee mitos y leyendas de México e identifica las características y funciones de cada tipo de texto.
• Investiga sobre el origen de los mitos y leyendas leídos.
• Identifica elementos de realidad y fantasía tanto en mitos como en leyendas.
• Indaga, con las personas adultas mayores de su comunidad, para conocer los mitos y leyendas que forman parte de la cultura de su región.
• Escenifica un mito o leyenda de su interés frente a público.
• Reflexiona sobre la riqueza cultural que encierran los mitos y las leyendas.',24),
  ('5','Ciencias Naturales','Saberes y Pensamiento Científico','Estructura y funcionamiento del cuerpo humano: sistemas circulatorio, respiratorio e inmunológico, y su relación con la salud ambiental, así como acciones para su cuidado.','• Describe y representa mediante modelos, la relación de la nariz, tráquea y pulmones, como parte del sistema respiratorio, con el intercambio de gases.
• Indaga y explica con modelos, la función general del corazón y los vasos sanguíneos (arterias y venas), que forman parte del sistema circulatorio y su relación con el intercambio de gases.
• Comprende que la frecuencia cardiaca es el número de latidos del corazón en un minuto, que se puede medir en los puntos en los que se ubican arterias (muñecas, cuello, tobillos) a través del pulso cardíaco; establece relaciones entre la actividad física y la frecuencia cardiaca.
• Indaga los factores del medio ambiente que inciden en la salud de los sistemas circulatorio y respiratorio; propone y practica acciones para prevenir infecciones y enfermedades y favorecer su cuidado.',25),
  ('5','Ciencias Naturales','Saberes y Pensamiento Científico','Etapas del desarrollo humano: proceso de reproducción y prevención de infecciones de transmisión sexual (ITS) y embarazos en adolescentes, en el marco de la salud sexual y reproductiva.','• Describe a la infancia, adolescencia, madurez y vejez como parte del desarrollo humano, así como las características, necesidades, responsabilidades, formas de pensar y cuidados generales en cada una de ellas.
• Comprende que el embarazo es resultado de una relación sexual, a partir de describir y representar con modelos el proceso general
• de la reproducción en los seres humanos: fecundación, embarazo y parto, que implica la toma de decisiones libres e informadas y su prevención y planificación es responsabilidad tanto de hombres como de mujeres, y que forma parte de sus derechos sexuales y reproductivos.
• Analiza diversas situaciones acordes a su contexto relacionadas con el ejercicio de la sexualidad para reconocerlo como un derecho de todas las personas, y de vivirla de manera libre, informada, segura como parte de la salud sexual.
• Argumenta acerca de la importancia de los vínculos afectivos, la igualdad, el respeto, la responsabilidad, y la comunicación en las relaciones de pareja, con la finalidad de prevenir violencia en el noviazgo y embarazos en la adolescencia, considerando su proyecto de vida y el inicio de la actividad sexual.',26),
  ('5','Ciencias Naturales','Saberes y Pensamiento Científico','Alimentación saludable: características de la dieta correcta, costumbres de la comunidad, riesgos del consumo de alimentos ultraprocesados, y acciones para mejorar la alimentación.','• Explica las características de la dieta correcta: variada, completa, equilibrada, inocua, suficiente, y las contrasta con sus hábitos de alimentación para tomar decisiones en beneficio de su salud.
• Indaga posibles riesgos de los hábitos de alimentación personales y familiares, como diabetes, hipertensión, colesterol elevado, entre otros; propone posibles cambios en su alimentación a partir de las alternativas que
• están disponibles en su localidad y en las prácticas de higiene relacionadas con la preparación y consumo de alimentos.
• Describe de dónde provienen y cómo se producen o procesan los alimentos que consume y los beneficios nutrimentales que estos tienen; diseña distintos menús basados en las características de la dieta correcta.
• Comprende que su alimentación está relacionada con las costumbres de la familia y los productos de consumo disponibles en su comunidad, a partir de compararla con otras formas de alimentación en diferentes regiones del país y con otros países.
• Analiza y explica la relación que tiene mantener una dieta correcta con el crecimiento y funcionamiento adecuado del organismo, así como para prevenir enfermedades no transmisibles como la diabetes o la hipertensión.',27),
  ('5','Ciencias Naturales','Saberes y Pensamiento Científico','Funciones vitales que caracterizan a plantas y animales como seres vivos, y su relación con el entorno natural, así como sus cambios a través del tiempo.','• Explica la reproducción en plantas por semillas, tallos, hojas, raíces y su interacción con otros seres vivos y el entorno natural; identifica y representa las estructuras de una flor que participan en la reproducción.
• Describe interacciones que ocurren entre los factores físicos y biológicos que intervienen en el proceso de reproducción de las plantas: polinización, dispersión de semillas y frutos, o germinación.
• Indaga el tipo de desarrollo y nacimiento de diversos animales (insectos, arácnidos, moluscos, aves, mamíferos, reptiles, peces y anfibios) para clasificarlos en vivíparos y ovíparos.
• Comprende que la reproducción es una función que caracteriza a todas las plantas y los animales como seres vivos.',28),
  ('5','Ciencias Naturales','Saberes y Pensamiento Científico','Factores que conforman la biodiversidad y el medio ambiente, la riqueza natural de México y su relevancia como parte del patrimonio biocultural de la humanidad, y la importancia de su conservación.','• Comprende que la biodiversidad es la cantidad y variedad de ecosistemas y de seres vivos (animales, plantas, hongos y bacterias); e identifica la cantidad total de especies identificadas hasta el momento por la ciencia a nivel mundial.
• Indaga los factores que favorecen la presencia en México de una variedad de ecosistemas y seres vivos, que lo hacen megadiverso; valora la importancia natural y sociocultural de su conservación.
• Describe los servicios ambientales de la biodiversidad: producción de oxígeno, regulación de climas, abastecimiento de agua, moderación en el impacto de fenómenos naturales, control de plagas, obtención de materias primas, espacios vitales para plantas y animales, espacios para actividades recreativas y culturales, entre otros.',29),
  ('5','Ciencias Naturales','Saberes y Pensamiento Científico','Pérdida de biodiversidad, problemas medio ambientales en la comunidad, México y el mundo, acciones orientadas a fortalecer estilos de vida sustentables.','• Analiza y explica el impacto de las actividades humanas en la biodiversidad, en particular sobre la variedad y cantidad de seres vivos que habitan en la comunidad, y en la salud.
• Analiza situaciones relacionadas con la pérdida de biodiversidad a nivel local y nacional, reconoce las causas y las consecuencias para la salud y la dinámica de los ecosistemas; identifica y explica prácticas locales y estrategias estatales o nacionales para el cuidado de la biodiversidad.
• Comprende la importancia que tiene la biodiversidad y el valor del cuidado de los seres vivos y las condiciones naturales que favorecen su existencia; propone y practica acciones, como el consumo responsable que favorecen su cuidado.',30),
  ('5','Física','Saberes y Pensamiento Científico','Costos y beneficios del consumo de agua, energía eléctrica y combustibles en la satisfacción de necesidades personales.','• Indaga y analiza la cantidad de agua que se consume en diversas actividades en la casa, compara su consumo diario e identifica en qué actividades se utiliza una mayor o menor cantidad de agua.
• Analiza problemas relacionados con el agua presentes en la casa, escuela y comunidad; reconoce la importancia de su consumo y practica acciones para aprovecharla de manera responsable.
• Reconoce y calcula la cantidad de “agua virtual” que se utiliza en la producción de satisfactores (productos y servicios) y reflexiona acerca del consumo de aquellos productos que son necesarios y aquellos que no lo son, para tomar decisiones de consumo responsable y favorecer el cuidado del medio ambiente.',31),
  ('5','Ciencias Naturales','Saberes y Pensamiento Científico','Propiedades de los materiales: dureza, flexibilidad y permeabilidad y su aplicación en la satisfacción de necesidades; caracterización de los gases con base en sus propiedades.','• Experimenta con diversos materiales las propiedades de dureza -resistencia que tiene al rayado y el corte en su superficie-, flexibilidad -cambio de forma al doblarse sin romperse- y permeabilidad -paso de un líquido a través de él sin que se altere su composición-.
• Relaciona las propiedades de dureza, flexibilidad y permeabilidad de los materiales con su uso, para la satisfacción de algunas necesidades; toma decisiones sobre cuál es el más adecuado y de las consecuencias de su uso excesivo para el medio ambiente.
• Diseña y construye objetos con base en las propiedades de dureza, flexibilidad y permeabilidad de algunos materiales (vidrio, papel, cartón, plástico, unicel o metales).
• Analiza la relevancia de los materiales como aporte de la ciencia y la tecnología en la satisfacción de necesidades, así como los efectos de su uso inadecuado o poco ético en el medio ambiente.',32),
  ('5','Ciencias Naturales','Saberes y Pensamiento Científico','Cambios permanentes en los materiales y sus implicaciones en la vida diaria.','• Describe que, un cambio temporal, implica la transformación de la forma e incluso de las propiedades de los materiales, pero no de su composición, mientras que, en un cambio permanente, las propiedades y composición de los materiales se modifican, por lo que no vuelven a su estado original, ya que se transforman en otros diferentes.
• Describe a la cocción y descomposición de los alimentos como cambios permanentes, a partir de experimentar con alimentos y la variación de la temperatura.
• Indaga y describe los beneficios de la cocción de alimentos, en función de las variables de temperatura y tiempo; así como, los factores que aceleran o retardan la descomposición de los alimentos y las implicaciones para la salud.
• Reconoce y valora las técnicas utilizadas por diferentes pueblos y culturas relacionados con la cocción y conservación de alimentos.',33),
  ('5','Física','Saberes y Pensamiento Científico','Efecto del magnetismo y de la fuerza de gravedad.','• Comprende que el magnetismo es una fuerza que actúa a distancia en los objetos, a partir de experimentar con imanes y el movimiento de objetos de diversos materiales.
• Describe las características de los imanes: polos (norte y sur) y sus efectos de atracción y repulsión; establece relaciones entre el tipo de materiales y el efecto de los imanes.
• Reconoce que la interacción de fuerzas magnéticas es la base de tecnologías modernas, incluidos motores eléctricos y generadores; indaga los cambios que su introducción ha significado en actividades humanas como la comunicación (celulares y WiFi) y el transporte.',34),
  ('5','Física','Saberes y Pensamiento Científico','Transformaciones de la energía térmica y eléctrica, así como su aplicación tecnológica.','• Comprende que el calor es una forma de energía, que fluye entre objetos con diferente temperatura al ponerlos en contacto, siempre del objeto de mayor al de menor temperatura.
• Describe, experimenta y representa diferentes tipos de transferencia de energía térmica: conducción y convección; identifica su aplicación en las actividades humanas.
• Analiza los beneficios y riesgos generados en el medio ambiente y en la salud por la generación y consumo de energía térmica.',35),
  ('5','Física','Saberes y Pensamiento Científico','Sistema Solar y Universo: características de sus componentes, y aportaciones culturales, científicas y tecnológicas que han favorecido su conocimiento.','• Indaga, describe y representa con modelos las características de forma, ubicación, color, tamaño, distancia al Sol, temperatura, masa, número de satélites naturales y anillos, entre otras, de los componentes del Sistema Solar: Sol, planetas, satélites y asteroides.
• Identifica y explica las características del movimiento de rotación y de traslación de los planetas y otros componentes del Sistema Solar: velocidad, dirección y trayectoria.
• Describe y valora diversas aportaciones culturales, científicas y tecnológicas, entre ellas, la invención del telescopio, para el conocimiento del Sistema Solar.',36),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Estudio de los números. Expresa oralmente la sucesión numérica hasta seis cifras, en español y hasta donde sea posible, en su lengua materna, de manera ascendente y descendente a partir de un número natural dado.','• A través de situaciones vinculadas a diferentes contextos ordena, lee, escribe e identifica regularidades en números naturales de hasta nueve cifras.
• Lee, escribe y ordena números decimales hasta diezmilésimos en notación decimal y letra, y los interpreta en diferentes contextos.
• Resuelve situaciones problemáticas que implican comparar y ordenar fracciones a partir de construir fracciones equivalentes al multiplicar o dividir al numerador y al denominador por un mismo número.
• Reconoce, interpreta y utiliza las fracciones 1/2, 1/4, 3/4, 1/5 y 1/8 expresados en notación decimal y viceversa en diferentes contextos.',37),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Suma y resta, su relación como operaciones inversas.','• Propone y resuelve situaciones problemáticas que implican sumas y restas con números decimales utilizando el algoritmo convencional y fracciones con diferentes denominadores.
• Utiliza, explica y comprueba sus estrategias para calcular mentalmente sumas y restas de dos números múltiplos de 100 y dos fracciones cuyos denominadores son múltiplos.',38),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Multiplicación y división, su relación como operaciones inversas.','• Resuelve situaciones problemáticas vinculadas a diferentes contextos que implican multiplicar números fraccionarios y números decimales, con un número natural como multiplicador.
• Resuelve situaciones problemáticas vinculadas a diferentes contextos que implican dividir números naturales y el cociente resulte un número decimal.',39),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Relaciones de proporcionalidad. Resuelve situaciones problemáticas de proporcionalidad en las que determina valores faltantes de números naturales, a partir de diferentes estrategias (cálculo del valor unitario, de dobles, triples o mitades).','• Resuelve situaciones problemáticas vinculadas a diferentes contextos que implican comparar razones expresadas con dos números naturales.
• Identifica que los porcentajes de 50%, 25%, 20%, 10% tienen relación con las fracciones 1/2, 1/4, 1/5, 1/10, a partir de resolver situaciones problemáticas que implican el cálculo de porcentajes.',40),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Cuerpos geométricos y sus características.','• Reconoce y describe semejanzas y diferencias entre un prisma y una pirámide; propone desarrollos planos para construir prismas rectos cuadrangulares o rectangulares.',41),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Figuras geométricas y sus características.','• Con el apoyo de instrumentos geométricos, construye círculos a partir de distintos datos (longitud del diámetro o del radio, a partir de dos puntos); distingue la diferencia entre circunferencia y círculo e identifica el diámetro y el radio.',42),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Medición de longitud, masa y capacidad.','• Resuelve situaciones problemáticas vinculadas a diferentes contextos que requieren calcular longitudes, masas o capacidades utilizando unidades convencionales, además del kilómetro y la tonelada.',44),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Perímetro, área y noción de volumen.','• Distingue unidades lineales de cuadráticas, al calcular, con el apoyo de retículas cuadriculadas, el perímetro y área de diferentes polígonos para reconocer que existen: a) figuras diferentes con el mismo perímetro y diferente área; b) figuras diferentes con la misma área y diferente perímetro; c) figuras diferentes con el mismo perímetro y con la misma área.
• Construye y usa fórmulas para calcular el perímetro de cualquier polígono, a partir de sumar la longitud de todos sus lados o multiplicar el número de lados por la medida de uno de ellos.
• Construye y usa fórmulas para calcular el área de rectángulos, romboides y triángulos; utiliza unidades convencionales (m² y cm²) para expresar sus resultados.',45),
  ('5','Matemáticas','Saberes y Pensamiento Científico','Organización e interpretación de datos.','• Construye tablas y gráficas de barras, e interpreta información cuantitativa y cualitativa contenida en ellas; interpreta la moda para responder preguntas vinculadas a diferentes contextos.',46),
  ('5','Geografía','Ética, Naturaleza y Sociedades','Valoración de la biodiversidad en el territorio donde se ubica la localidad, entidad, México y el mundo, valores y acciones sustentables.','• Comprende la biodiversidad, su función como elemento vital en la Tierra y en el equilibrio de la biosfera, así como la importancia para la vida humana y de las demás especies.
• Compara e interpreta representaciones cartográficas de la biodiversidad de México, su entidad y localidad, reconociendo su distribución y los elementos que la hacen posible (características y dinámica del suelo, tipo de clima, altitud, latitud y continentalidad, entre otros).
• Indaga cómo y por qué está desapareciendo la biodiversidad, incluyendo los cambios del clima global y sus riesgos para la vida.
• Propone y realiza acciones que ayuden a proteger la biodiversidad, de acuerdo con sus posibilidades, desde una perspectiva crítica.',49),
  ('5','Geografía','Ética, Naturaleza y Sociedades','Valoración de la megadiversidad mexicana: megadiversidad en México, diversidad cultural, relaciones ser humano-naturaleza y representaciones distintas de las diferentes culturas o grupos sociales, sobre la biodiversidad y su manejo, acorde a sus contextos.','• Comprende por qué México es un país biodiverso y biocultural, así como la biodiversidad local y su influencia en las tradiciones culturales de la comunidad (cultivos, alimentos, indumentaria, herbolaria, fiestas, ritos, entre otras).
• Reconoce que los grupos sociales generan conocimientos distintos sobre la biodiversidad y su manejo, acorde a sus contextos y que éstos influyen en la conformación de culturas diversas con formas propias de representar el mundo, la vida y sus relaciones con la naturaleza, entre sí y con los otros.',50),
  ('5','Geografía','Ética, Naturaleza y Sociedades','Sustentabilidad de la biodiversidad y humanismo: rasgos de los estilos de vida y modelos de desarrollo dominantes y su impacto en la biodiversidad, implicaciones socioambientales de la preservación.','• Analiza críticamente estilos de vida y modelos de desarrollo dominantes en las sociedades del mundo y de México a través del tiempo, así como su impacto desfavorable en la biodiversidad y el ambiente de su comunidad y del país (plantas, animales, suelos, aire, cuerpos de agua, manglares, agricultura, salud humana, entre otros).
• Argumenta críticamente cómo es que, bajo el ideal de satisfacer las necesidades humanas, los patrones de producción y venta de consumibles se vinculan con la extracción de los bienes naturales, el consumo irracional de energía
• en su procesamiento y desecho, y los riesgos ambientales locales y globales.
• Reflexiona acerca de los valores e implicaciones socioambientales de la mercantilización de la biodiversidad, e identifica otros valores y formas de relación con la naturaleza, cuya prioridad sea la de cuidar su estabilidad y construir un mundo más seguro y humanista.',51),
  ('5','Geografía','Ética, Naturaleza y Sociedades','Ética y biodiversidad: factores sociales que propician la convivencia armónica con el medio ambiente basada en el respeto, responsabilidad, justicia social y equidad con la naturaleza.','• Dialoga acerca de los valores que necesitamos promover para conservar y proteger a la biodiversidad.
• Elige y pone en práctica, de manera crítica, acciones de bienestar común para la regeneración y preservación de su biodiversidad en la vida cotidiana, promoviendo que autoridades, personas y familias de su comunidad, colaboren responsablemente para el logro de tal fin.
• Dialoga y construye juicios éticos acerca de los derechos de los seres vivos, y establece compromisos para su trato respetuoso y digno, así como su protección y preservación.',52),
  ('5','Geografía','Ética, Naturaleza y Sociedades','Derechos humanos: a un ambiente sano y acceso al agua potable.','• Dialoga acerca del derecho humano a un ambiente sano y adecuado para su desarrollo y bienestar.
• Investiga la relación entre el derecho a un ambiente sano y las soluciones locales basadas en el trabajo colectivo, crítico y justo, para restaurar o reducir la destrucción de la biodiversidad y promover en la escuela, barrio, pueblo o ciudad, su respeto, con responsabilidad y colaboración para protegerla, y aprovecharla de manera sustentable, con equidad y justicia social.',53),
  ('5','Geografía','Ética, Naturaleza y Sociedades','La responsabilidad compartida, el respeto y el consumo sustentable: acciones colectivas a favor de la protección, regeneración y preservación de la biodiversidad y el bienestar socioambiental.','• Comprende el largo camino que recorren los productos para llegar a sus hogares, los medios que se utilizan para imponer patrones de consumo y la importancia de consumir lo local, eligiendo lo que compramos de manera responsable y consciente.',54),
  ('5','Geografía','Ética, Naturaleza y Sociedades','Riesgos de desastre y crisis humanitarias, asociados a fenómenos naturales y generados por acciones humanas: sus causas y consecuencias, para contribuir, de manera solidaria, a minimizar sus efectos.','• Comprende que los desastres no son naturales, sino eventos repentinos que ocasionan daños materiales, humanos y sociales, y que sus efectos pueden ser prevenidos o mitigados.
• Identifica algunos componentes de un desastre, tales como los agentes perturbadores, que pueden ser de origen natural o humano; los agentes afectables, representados por la infraestructura y la comunidad; y los agentes reguladores, que son las instituciones encargadas de dar protección y ayuda a las personas afectadas.
• Identifica en mapas de la localidad y la entidad, zonas de seguridad, y describe las rutas para llegar a ellas.
• Comprende que los efectos de los desastres dependen de las decisiones que las personas tomen, tanto en sus vidas como para su entorno; por ejemplo, cómo y dónde se producen los alimentos y se construyen las viviendas, lo que puede constituir un riesgo, así como cuáles son los programas de gobierno destinados a la prevención, atención y reconstrucción en caso de desastre.
• Reflexiona y dialoga acerca de las responsabilidades compartidas, para la reducción del riesgo de desastres, con relación a qué le corresponde a la ciudadanía, a las autoridades, al gobierno, a empresarias y empresarios, a las organizaciones de la sociedad civil, así como, la importancia de participar en acciones individuales y colectivas encaminadas a la prevención en su comunidad.
• Promueve la empatía con personas que han vivido una situación de desastre, y organiza acciones de ayuda.',55),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Construcción de la cultura de paz: análisis de conflictos vecinales y/o territoriales del pasado y del presente entre personas, grupos, comunidades y pueblos para identificar sus causas, cómo se desarrollaron y cómo se resolvieron, destacando el diálogo, la negociación y la tolerancia.','• Indaga en fuentes orales, escritas o digitales acerca de conflictos vecinales entre personas y/o grupos de su comunidad, barrio, colonia o ciudad que han ocurrido en años recientes. Analiza críticamente las causas, desarrollo y resolución del conflicto.
• Representa de forma gráfica o artística el proceso que ha seguido el conflicto.
• Identifica la negociación, la mediación, el diálogo y la empatía, como formas pacíficas para resolver conflictos, y las aplica en algunos ejemplos de conflictos cotidianos de su escuela o comunidad.
• Argumenta por qué es necesario resolver los conflictos, privilegiando el diálogo, la empatía, la negociación y la mediación para erradicar la violencia y promover la cultura de paz.',56),
  ('5','Historia','Ética, Naturaleza y Sociedades','La democracia como forma de gobierno en México y su construcción a través de la historia.','• Indaga acerca de las transformaciones en las formas de gobierno de nuestro país, durante el siglo XIX, destacando las luchas entre federalistas y centralistas, mismas que sentaron las bases para la constitución de una República representativa, democrática, laica y federal; así como la participación política de las mujeres en México en el siglo XIX.
• Argumenta por qué se requiere de la participación de todas las personas y pueblos que integran una sociedad, considerando el carácter pluricultural y lingüístico del país, para que la democracia sea una forma de vida, en los distintos ámbitos de convivencia.',57),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Cultura democrática: principios éticos que subyacen en los acuerdos, normas y leyes democráticas, importancia de su cumplimiento y evaluación de su aplicación justa, equitativa e igualitaria en la vida cotidiana.','• Comprende que la cultura democrática se sustenta en acuerdos, normas y leyes que expresan los principios éticos de igualdad, respeto, responsabilidad, libertad, justicia, honestidad, legalidad, interculturalidad, inclusión, entre otros. Analiza críticamente algunos ejemplos de acuerdos, normas y leyes que expresan los principios democráticos.
• Argumenta en favor del cumplimiento de los principios éticos y analiza, de forma crítica, los beneficios que aportan en los ámbitos personal y colectivo, así como en la interrelación de la sociedad.',58),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Desafíos para la construcción de sociedades inclusivas y equitativas: la violencia de género como un problema estructural, con un peso social, cultural e histórico, a fin de visibilizar sus causas y consecuencias, para erradicarlas,','• Analiza críticamente las causas y consecuencias sociales, culturales e históricas de la violencia de género, asociadas a estereotipos o prejuicios sobre la feminidad y la masculinidad en sociedades y comunidades patriarcales, que pueden llevar a un trato desigual.
• Dialoga sobre cómo transformar los estereotipos o prejuicios de género, para desarrollar masculinidades positivas, que contribuyan a',59),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','buscando la equidad como derecho.','• la construcción de comunidades y sociedades inclusivas, equitativas y libres de violencias.',60),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Contribuciones al bienestar colectivo: servicios públicos e infraestructura para satisfacer las necesidades de salud, educación, esparcimiento, comunicación, seguridad y justicia de las personas que habitan la comunidad y el país, así como la rendición de cuentas y el uso transparente de los recursos como parte de una sociedad democrática.','• Indaga acerca de las necesidades de salud, esparcimiento, comunicación, seguridad y justicia de las personas de su comunidad, e identifica la infraestructura y servicios públicos que se requieren para satisfacerlas y alcanzar el bienestar colectivo.
• Identifica de qué manera las personas contribuyen con sus aportaciones y trabajo al funcionamiento de los servicios públicos.
• Dialoga acerca del derecho al acceso a la información pública: en qué consiste, por qué es importante y cómo se puede ejercer.',61),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','El derecho a la protección de la integridad física y mental, ante cualquier forma de maltrato, abuso o explotación de tipo sexual o laboral, así como, la identificación de personas e instituciones que pueden apoyar para el ejercicio de ese derecho.','• Reconoce el derecho de niñas, niños y adolescentes a la protección, al respeto de su integridad y de sus datos personales.
• Identifica la importancia de hacer valer sus derechos, así como a las personas, instituciones y leyes que promueven el respeto a los derechos de todas las personas para su bienestar.',62),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','La lucha por el reconocimiento de los derechos humanos: la protección de la dignidad de todas las personas y grupos sociales para vivir con gozo y armonía, sin importar las diferencias.','• Indaga en fuentes primarias y secundarias, orales, escritas, bibliográficas, hemerográficas, digitales, objetos, entre otras situaciones del pasado y del presente que den cuenta de demandas y luchas sociales de personas y grupos por el reconocimiento de sus derechos humanos como el derecho al voto de las mujeres, los derechos de los trabajadores, el reconocimiento de los grupos LGBTTTIQ+, pueblos originarios entre otros. Identifica las consecuencias de no respetar los derechos de las personas y se compromete a promover su respeto en sus distintos ámbitos de convivencia (familia, escuela y comunidad).',63),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Cumplimiento de los derechos humanos: estudio de casos de actos de discriminación, racismo o violencias que suceden','• Analiza críticamente un caso de racismo, discriminación o violencias en México, identificando las causas y las consecuencias culturales, económicas, políticas y sociales que se derivan del análisis, y propone acciones solidarias',64),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','actualmente en México y el mundo.','• que favorezcan el respeto y el cumplimiento de los derechos humanos.',65),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Valores y prácticas de los pueblos originarios y afromexicanos: el respeto, la reciprocidad y el beneficio mutuo como valores fundamentales de la relación con la naturaleza y con otras personas.','• Dialoga acerca de las características de la convivencia, sustentada en la práctica del respeto, la reciprocidad y el beneficio mutuo, en la relación armónica con la naturaleza, y con otros seres humanos.
• Identifica experiencias de convivencia en algunos pueblos originarios, afromexicanos o grupos urbanos, a fin de valorar los beneficios de esta forma de interacción, para practicar el buen vivir.',66),
  ('5','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Pueblos y culturas de América y el mundo: el respeto a las costumbres, tradiciones y formas de vivir de diferentes culturas.','• Explora la vida cotidiana de pueblos originarios, comunidades y grupos sociales de diferentes lugares del Continente Americano, del pasado y el presente.
• Identifica cambios y permanencias de diversas identidades culturales y cosmovisiones, que expresan formas de relacionarse con los demás, con la naturaleza, con el cosmos y consigo mismo.
• Localiza el Continente Americano y describe las características (clima, relieve, aguas continentales y oceánicas, poblaciones, diversidad sociocultural y lingüística).
• Reconoce los criterios a partir de los cuales el Continente Americano se subdivide en regiones geográficas de América del Norte, América Central, las Antillas y Sudamérica o América del Sur, así como sus rasgos culturales y algunos procesos históricos vividos en lo que se ha denominado América anglosajona y América Latina, identificando algunas causas de las desigualdades sociales, económicas y educativas entre ambas regiones.',67),
  ('5','Historia','Ética, Naturaleza y Sociedades','Movimientos sociales en el México de los siglos XIX y XX: la Independencia y la Revolución Mexicana.','• Indaga en fuentes bibliográficas, hemerográficas, digitales y fotográficas, las causas del movimiento de independencia, la injusticia social, las confrontaciones ideológicas entre grupos de criollos y peninsulares.
• Dialoga acerca de los ideales que impulsaron el movimiento independentista, tales como la libertad, la justicia, la abolición de la esclavitud, la igualdad de derechos y la defensa de la soberanía.
• Analiza la participación de las y los protagonistas del movimiento de independencia, por ejemplo: Miguel Hidalgo y Costilla, Josefa Ortiz de Domínguez, José María
• Morelos y Pavón, Ignacio Allende, Leona Vicario, Vicente Guerrero y Agustín de Iturbide.
• Analiza la participación de grupos no visibilizados: personas esclavizadas, pueblos originarios, afrodescendientes, migrantes, mujeres, niñas, niños, jóvenes y personas adultas mayores, entre otros.
• Identifica acontecimientos, personas y lugares representativos desde el inicio hasta la consumación de la independencia de México, reconociendo los cambios en el territorio de lo que aún se denominaba la Nueva España.
• Dialoga acerca de cómo la construcción de una identidad nacional, denominada mexicana, impactó en la constitución de las identidades culturales de los pueblos originarios y afrodescendientes que habitaban nuestro territorio.
• Representa en mapas, los lugares estratégicos y emblemáticos de las luchas por la independencia, así como, las rutas seguidas por los personajes que encabezaron este movimiento.',68),
  ('5','Historia','Ética, Naturaleza y Sociedades','México independiente: la vida cotidiana, las intervenciones extranjeras durante el siglo XIX, causas y consecuencias de conflictos territoriales, la defensa de la soberanía nacional y la conformación del estado laico. ()','• Indaga en fuentes bibliográficas, hemerográficas, iconográficas, objetos y construcciones acerca de la vida cotidiana en el México independiente, qué estragos dejó la guerra en las familias, comunidades y pueblos, cómo vivían las personas, cómo eran los pueblos y ciudades donde vivían, cuáles eran los principales trabajos y oficios, cómo era la educación de niñas y niños, cómo se divertían las personas, entre otros aspectos.
• Indaga acerca de los inicios del México independiente, cuáles eran las condiciones sociales, económicas, políticas y culturales, por qué se designó a Iturbide como emperador, identificar el contexto internacional, qué países querían dominar a México y el impacto en
• el territorio nacional de las invasiones extranjeras.
• Analiza causas y consecuencias de las invasiones al territorio mexicano por los Estados Unidos de América: la Guerra de Texas y la apropiación del territorio, así como las implicaciones del Tratado de Guadalupe-Hidalgo en la modificación de los límites territoriales de nuestro país.
• Dialoga acerca del papel de las instituciones, como el de la Marina en la intervención de la defensa del puerto de Veracruz, y de los grupos sociales que lucharon por la defensa de la soberanía nacional ante las invasiones extranjeras.
• Indaga sobre las causas y las implicaciones sociales de la intervención francesa, así como de la constitución del segundo imperio mexicano, con Maximiliano de Habsburgo.
• Indaga sobre las causas y las implicaciones sociales en la restauración de la República.
• Reconoce el papel de Benito Juárez en la construcción y el establecimiento de las Leyes de Reforma (1859), mismas que sentaron las bases para la constitución de un estado laico en México.
• Conoce y dialoga acerca de las implicaciones de una educación laica, crítica y sin dogmas.',69),
  ('5','Geografía','Ética, Naturaleza y Sociedades','Migración y derechos humanos: migración interna y externa, causas y consecuencias sociales, económicas, culturales, políticas y ambientales.','• Reconoce los procesos de migración que se realizan en el territorio nacional (interna) y de México hacia otros países (externa).
• Analiza noticias, documentales y testimonios de personas migrantes, que le permitan identificar algunos de los motivos (sociales, económicos, políticos, culturales y/o ambientales), que originaron su desplazamiento, así como las características del lugar del destino al que pretende llegar.
• Ubica en mapas, las rutas que siguen los migrantes, desde su lugar de origen, hasta su destino.
• Reflexiona acerca de los impactos de las migraciones en la identidad y pertenencia de las personas, así como, los prejuicios que generan aspectos como la discriminación.
• Dialoga acerca de las dificultades que enfrentan las personas migrantes, para ejercer sus derechos humanos.
• Identifica algunos tratados internacionales que protegen los derechos de todas las personas, sin distinción de su condición migratoria.
• Describe las acciones que se podrían implementar para la protección de los derechos de las personas migrantes.',71),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Las familias como espacio para el desarrollo del sentido de pertenencia y autonomía, para una sana convivencia.','• Participa en distintas formas de convivencia en la familia, para fortalecer su sentido de pertenencia y afecto.
• Reflexiona acerca de los valores heredados de la familia, para el desarrollo de una sana convivencia en la escuela y la comunidad.',73),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Alternativas ante conflictos y problemas de la vida en la comunidad.','• Reflexiona sobre los conflictos que tiene en la escuela y la familia, para valorar las posibles alternativas de solución.
• Valora la pertinencia del diálogo, para solucionar los conflictos interpersonales.',74),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','La escuela como ventana hacia el futuro.','• Intercambia experiencias de estudio, para visualizar las opciones que tiene en su futuro.
• Reflexiona sobre sus preferencias, para imaginar sus proyectos de vida.',75),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','La comunidad, como espacio para el aprendizaje y el bienestar común.','• Argumenta la pertinencia y vigencia de las ideas, conocimientos y prácticas culturales de su comunidad, para valorar sus beneficios en el bienestar común.
• Experimenta diferentes tipos de organización, medios, recursos y procesos, para contribuir en el desarrollo sustentable de su comunidad.',76),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Formas de ser, pensar, actuar y relacionarse.','• Reflexiona acerca de las formas de ser, pensar, actuar y relacionarse que tienen las personas y los factores que las originan para propiciar el entendimiento mutuo.',77),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Construcción del proyecto de vida. Replantea las formas de satisfacer las necesidades e intereses, para promover la autodeterminación orientada al cumplimiento de metas.','• Analiza los intereses individuales y aquellos que comparte, para identificar situaciones en las que se requiere pedir apoyo y en las que se pueden acordar propuestas conjuntas.',78),
  ('5','Educación Física','De lo Humano y lo Comunitario','Capacidades, habilidades y destrezas motrices.','• Reconoce posibilidades y límites al participar en situaciones de juego e iniciación deportiva, individuales y colectivas, para valorar su desempeño y determinar posibles mejoras.',81),
  ('5','Educación Física','De lo Humano y lo Comunitario','Potencialidades cognitivas, expresivas, motrices, creativas y de relación.','• Integra sus capacidades y habilidades en situaciones lúdicas y expresivas (individuales y colectivas), para lograr mayor seguridad y confianza.',82),
  ('5','Educación Física','De lo Humano y lo Comunitario','Pensamiento lúdico, estratégico y creativo.','• Planifica e implementa estrategias ante situaciones de juego y cotidianas, para contar con opciones que incrementen la efectividad de su actuación.',84),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Acciones individuales que repercuten en la conservación y mejora de la salud.','• Construye alternativas saludables y sostenibles asociadas con hábitos de higiene personal y limpieza de los espacios, para promover la toma de conciencia sobre su impacto en el bienestar personal y social.
• Analiza los hábitos alimentarios presentes en la familia y comunidad, para valorar su impacto en favor de un consumo responsable.
• Practica diversas estrategias que permiten reaccionar a cambios o afrontar situaciones de riesgo relacionadas con accidentes, adicciones y formas de violencia, para favorecer el bienestar personal y colectivo.',86),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Sentido de comunidad y satisfacción de necesidades humanas.','• Argumenta acerca de la pertinencia de ideas, conocimientos y prácticas culturales de la comunidad, para valorar sus beneficios y áreas de oportunidad en favor del bienestar individual y colectivo.
• Experimenta formas de organización y representación gráfica, así como medios, recursos y procesos empleados en la satisfacción de necesidades, con el fin de proponer mejoras orientadas a fomentar el desarrollo sostenible.',87),
  ('5','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Toma de decisiones y creatividad, ante problemas de la vida.','• Describe los problemas que se presentan en su vida, para reflexionar sobre posibles soluciones.
• Reflexiona sobre las posibles alternativas de solución ante problemas para analizar la toma de decisiones.
• Valora si en la toma de decisiones interviene causa-efecto para establecer causalidades del problema o se sustenta en el juicio crítico.',88),
  ('5','Desarrollo personal','De lo Humano y lo Comunitario','Los afectos y su influencia en el bienestar.','• Distingue los factores que influyen en el estado de ánimo y la vida cotidiana, para mejorar la convivencia y el autocuidado.
• Explora las reacciones emocionales ante diversas situaciones y contextos para mejorar la convivencia.',89),
  ('6','Español','Lenguajes','Narración de sucesos autobiográficos.','• Lee textos autobiográficos e identifica las relaciones temporales de secuencia, simultaneidad y duración.
• Analiza distintos sucesos de su vida para elegir los más significativos y organizarlos de manera coherente en una narración.
• Determina al destinatario y la forma en que desea narrar sucesos autobiográficos significativos, para causar efectos particulares.
• Usa reflexivamente adverbios, frases adverbiales y nexos temporales, para indicar secuencia, simultaneidad y duración en los sucesos narrados.
• Colabora en la edición de un libro de textos autobiográficos, y sugiere formas de reproducirlo para que cada alumna y alumno tenga el suyo.',1),
  ('6','Español','Lenguajes','Comprensión y producción de textos explicativos.','• Localiza y lee textos explicativos de temas variados.
• Expresa con sus palabras las ideas que comprende de los textos que lee y elabora resúmenes que le permitan reconstruir las ideas principales y los elementos de los textos explicativos.
• Reconoce y emplea relaciones de causa-consecuencia.
• Emplea palabras como primero, finalmente, luego, después, posteriormente, durante, para organizar las oraciones.
• Utiliza palabras nuevas y/o técnicas en el texto explicativo que produce para compartir.',2),
  ('6','Español','Lenguajes','Participación en debates sobre temas de interés común.','• Prepara su participación en un debate y formula los argumentos por presentar, cuidando que la exposición del tema por discutir resulte coherente y suficiente, los argumentos claros, pertinentes y fundamentados, y se expliciten las referencias bibliográficas y citas textuales que dan soporte a la información que se comparte.
• Identifica la función de los conectivos causales, temporales y lógicos en textos argumentativos.
• Escucha y opina de manera crítica durante su desempeño como participante, moderador, moderadora o público en un debate.',3),
  ('6','Español','Lenguajes','Comprensión y producción de textos argumentativos.','• Lee textos sobre temas polémicos, e identifica los argumentos que sustentan cada postura.
• Registra los principales argumentos y las conclusiones de las autoras y los autores de los textos leídos.
• Reflexiona sobre la relación entre los argumentos principales y las conclusiones.
• Escribe un texto, a partir de las ideas que registró, en el que expresa sus propias opiniones sobre los temas tratados, y en el que emplea nexos que anteceden los argumentos, como porque, ya que, si bien, en consecuencia.',4),
  ('6','Español','Lenguajes','Comprensión y producción de textos informativos, para ampliar sus conocimientos sobre temas de interés tanto colectivo como individual.','• Lee textos informativos y reflexiona sobre su organización.
• Identifica información específica sobre asuntos de su interés, y comprende el tema central.
• Reconoce vínculos entre el contenido de textos informativos, respecto del contraste, la complementariedad y la causa-consecuencia del tema abordado.
• Escribe textos informativos en los que registra, de manera convencional, los datos de las fuentes consultadas: autor, título, editorial, fecha y lugar de publicación, páginas consultadas, etcétera.',5),
  ('6','Español','Lenguajes','Comprensión y producción de textos discontinuos, para organizar y presentar información.','• Reconoce, mediante el análisis, las características y funciones de los textos discontinuos, en particular de gráficas, cuadros sinópticos y mapas conceptuales.
• Reflexiona sobre las posibilidades de los textos discontinuos para organizar la información que expone a otras personas.
• Sintetiza información, sin perder el significado original, para organizarla y presentarla por medio de textos discontinuos.
• Produce textos discontinuos, considerando al destinatario y empleando elementos gráficos útiles para organizar y presentar información, como tipografía, viñetas, espacios de la página, interlineado, signos de puntuación, mayúsculas y minúsculas.',6),
  ('6','Artes','Lenguajes','Elaboración e intercambio de reseñas de diversos textos y/o audiovisuales.','• Explica la utilidad de las reseñas y comenta sus características.
• Describe el material audiovisual consultado y registra los datos de identificación de este: título, tema, director, protagonistas, institución o empresa productora, fecha de realización, etcétera.
• Elabora una opinión sustentada acerca de un material reseñado.
• Usa conectores como porque, ya que, puesto que, por, debido a, etcétera, con los que apoya la argumentación de sus opiniones.
• Revisa y corrige reiteraciones innecesarias, y errores de concordancia y ortografía en general.',7),
  ('6','Español','Lenguajes','Comparación y producción de documentos que regulan la convivencia.','• Reconoce la función e importancia de cumplir las pautas o normas establecidas en reglamentos para regular la convivencia.
• Reflexiona y comprende la concisión de las reglas, el empleo de verbos (modo y tiempo) y el uso de numerales.
• Escribe las reglas para lograr una convivencia respetuosa, incluyente, equitativa e igualitaria
• en la escuela, tomando en consideración sus experiencias a lo largo de la primaria.
• Utiliza oraciones breves y decide si debe emplear subtítulos, viñetas o incisos.
• Revisa y corrige errores en cuanto al contenido, concordancia y ortografía en el texto, hasta que logra la versión final del reglamento escolar.',8),
  ('6','Español','Lenguajes','Exposición sobre temas relacionados con el cuidado de la salud.','• Como presentador o presentadora
• -Elabora un guion para presentar de manera ordenada la información que investigó en diversas fuentes, gráficas, orales y/o escritas, y usó para construir su exposición.
• -Prepara diversos materiales de apoyo para enriquecer su presentación.
• -Usa un léxico formal y mantiene o recupera la atención de la audiencia haciendo inflexiones de voz, ademanes, gestos, preguntas.
• -Aclara las dudas que le plantean y, en general, atiende los comentarios u opiniones que le comparten acerca de lo expuesto.
• Como audiencia
• -Comprende lo que escucha, apunta lo que le interesa, pregunta y comenta sobre lo expuesto, y argumenta sus opiniones y divergencias.',9),
  ('6','Español','Lenguajes','Producción y envío de cartas personales.','• Lee distintas cartas personales reales y literarias y analiza sus características.
• Discute sobre las similitudes y diferencias, así como sobre las ventajas y desventajas del correo postal y el electrónico.
• Reconoce la estructura de la información de las direcciones postales y electrónicas de destinatarias, destinatarios y remitentes.
• Expresa sentimientos, ideas y experiencias por medio de cartas, en función de las destinatarias y los destinatarios y empleando adverbios de tiempo y lugar: ayer, hoy, mañana, anoche, ahora, después, luego, nunca, jamás, aquí, allá, allí, arriba, abajo.
• Envía las cartas que escribe a través del correo postal y/o electrónico.',10),
  ('6','Español','Lenguajes','Interpretación y producción de anuncios publicitarios de productos o servicios ofrecidos en la comunidad.','• Recopila y analiza anuncios publicitarios elaborados con distintos fines; por ejemplo, comerciales, políticos y sociales.
• Reflexiona sobre las características y funciones de las frases publicitarias empleadas en anuncios publicados en medios impresos y electrónicos, y analiza el uso de estereotipos, frases sugestivas, juegos de palabras y demás recursos lingüísticos y gráficos.
• Adopta una postura crítica ante los mensajes publicitarios y discute sobre ella con sus compañeras y compañeros.
• Elabora anuncios publicitarios sobre los productos y servicios ofrecidos en su comunidad, en los que considera la disposición gráfica y el uso de adjetivos, frases adjetivas, adverbios y figuras retóricas como analogías, metáforas, comparaciones, rimas, hipérboles y demás juegos de palabras.
• Difunde con las personas de la comunidad los anuncios publicitarios elaborados, así como su postura crítica ante los mensajes publicitarios analizados.',11),
  ('6','Español','Lenguajes','Seguimiento crítico de noticias en diferentes medios de comunicación escrita.','• Consulta distintos medios de comunicación escrita y selecciona noticias de su interés, justificando las razones de su elección.
• Da seguimiento a las noticias de su interés en distintos medios de comunicación escrita e identifica las fuentes de las que proviene la información: testimonios, agencias de noticias, otros diarios y revistas.
• Identifica relaciones de contraste, complementariedad, causa-consecuencia y temporalidad entre las diferentes notas informativas sobre el mismo hecho noticioso.
• Reflexiona sobre las diferentes formas de expresar y abordar el mismo hecho noticioso en diferentes medios de comunicación escrita: extensión, manera de presentarlo, opiniones de las autoras y los autores, tipo de información que se revela.
• Escribe y comparte sus conclusiones sobre el hecho noticioso y sus reflexiones sobre las razones por las que pueden presentarse de diferente manera en cada medio de comunicación escrita.',12),
  ('6','Español','Lenguajes','Comprensión y producción de textos para gestionar servicios públicos.','• Dialoga con sus pares sobre los servicios públicos que podrían gestionar para mejorar su entorno natural y social, define con sus compañeras y compañeros cuál gestionarán y averiguan a qué persona o institución deben dirigirse.
• Reflexiona sobre las características de las cartas formales.
• Escribe con sus compañeras y compañeros una carta formal, en la que explican, por un lado, el servicio público que solicitan, y, por otro, las razones.
• Emplea mayúsculas al inicio de los párrafos y de los nombres propios, así como punto y seguido, punto y aparte, dos puntos y coma para ordenar las oraciones y los párrafos.
• Envía, con apoyo del profesor o profesora, la carta formal y le da seguimiento a la solicitud.',13),
  ('6','Español','Lenguajes','Elaboración de un tríptico informativo sobre la prevención de algún problema colectivo.','• Indaga y reflexiona sobre las características y funciones de los trípticos informativos.
• Investiga en diferentes fuentes impresas y electrónicas, y por medio de entrevistas con personas de la comunidad, sobre algún problema colectivo que pueda prevenirse y sobre las maneras de lograrlo.
• Comparte con sus compañeras y compañeros la información investigada y dialoga para que, entre todos y todas, reflexionen sobre la relevancia de la prevención y elijan el problema colectivo sobre el que harán un tríptico informativo.
• Investiga con mayor profundidad sobre el problema colectivo que hayan elegido e integran la información en un texto breve que incluirán en un tríptico que contenga portada, imágenes, gráficas, tablas, cuadros, fuentes de consulta, datos de personas o instituciones de apoyo, etcétera.
• Presenta y difunde el tríptico con la comunidad.',14),
  ('6','Español','Lenguajes','Reconocimiento de la diversidad lingüística de México.','• Identifica qué lenguas se hablan en su familia, localidad y/o región.
• Investiga sobre las lenguas que se hablan en su familia, localidad y/o región, por medio entrevistas y fuentes impresas y electrónicas.
• Escribe un texto sobre los resultados de su investigación, empleando comillas para diferenciar las palabras de otras y otros de las suyas, e incluyendo las referencias de las fuentes consultadas. Comparte el resultado de su investigación.
• Reflexiona sobre las diferentes formas de valorar las lenguas en diversos contextos y sobre las posibles razones por las que esto ocurre.',15),
  ('6','Artes','Lenguajes','Interpretación y valoración de manifestaciones culturales y artísticas de México y del mundo.','• Reconoce ideales y temáticas sociales que se imprimieron en ciertas manifestaciones culturales y artísticas, en un tiempo y espacio determinados.
• Analiza las partes y elementos que conforman una manifestación cultural o artística, y reconoce la multiplicidad de significados, puntos de vista y concepciones del mundo en ella.
• Reconoce símbolos presentes en manifestaciones culturales y artísticas, a partir del análisis e interpretación de formas, colores, texturas, sonidos, objetos, aromas, movimientos y gestos, que contienen.',16),
  ('6','Artes','Lenguajes','Apropiación e intervención artística en el espacio comunitario.','• Reflexiona en colectivo acerca de las maneras en que un espacio puede ser mejorado, y lo lleva a cabo mediante la planeación de expresiones artísticas, tales como performance, videoarte, instalación, escultura, o teatro comunitario.
• Representa en colectivo problemas de la comunidad para visibilizarlas mediante propuestas artísticas ante los demás.
• Crea producciones artísticas con distintos lenguajes: oral, escrito, alternativo, musical, visual, teatral o dancístico, para transformar de manera efímera, o incluso permanentemente, un espacio público de la comunidad, a favor del bienestar social.',17),
  ('6','Literatura','Lenguajes','Análisis de cuentos y poemas para su disfrute y comprensión.','• Selecciona y lee cuentos y poemas del mundo a partir de sus intereses y gustos.
• Intercambia con sus pares los cuentos y poemas que más le gustaron, y discute sobre su significado.
• Reconoce las características tanto de cuentos como de poemas.
• Elabora una antología con los cuentos y poemas seleccionados, así como con cuentos de producción propia, que incluya título, portada, portadilla, índice, ilustraciones, comentarios sobre la interpretación de cada texto y nombres de las y los participantes.
• Comparte la antología con la comunidad educativa y deja un ejemplar en la biblioteca escolar.',18),
  ('6','Artes','Lenguajes','Combinación de elementos visuales, sonoros y corporales, en composiciones artísticas colectivas, para expresar rasgos de sus identidades personal y colectiva.','• Combina formas, colores, texturas, sonidos, movimientos y gestos para representar personajes, lugares y situaciones y los guarda en video o los presenta en vivo al montar una exposición en la que se invite a familiares y el resto de la comunidad escolar, para su apreciación y disfrute.
• Recrea lugares y experiencias significativas, a partir de una composición visual colectiva que sonoriza con objetos a su alcance, mientras la narra en un audiovisual.
• Combina secuencias de formas, colores, texturas, sonidos, movi-
• movimientos, gestos y objetos, para explorar distintas maneras de expresar, en colectivo, una misma experiencia con distintos elementos.',19),
  ('6','Artes','Lenguajes','Expresión, mediante el uso de los lenguajes artísticos, de experiencias estéticas que tienen lugar en la naturaleza.','• Utiliza formas, colores, texturas, sonidos y movimientos, para expresar las emociones que surgen de una experiencia significativa en el entorno natural y las representa en colectivo mediante un mural o performance.
• Aprecia la disposición de formas, colores, texturas, sonidos y movimientos en el entorno natural y usa elementos de los lenguajes artísticos para representar una experiencia significativa de sus vínculos con la naturaleza.',20),
  ('6','Artes','Lenguajes','Creación y representación de narrativas a partir de acontecimientos relevantes de la comunidad, empleando recursos literarios, visuales, corporales y sonoros.','• Representa un acontecimiento de la comunidad, experimentando con movimientos suaves, fuertes, rápidos, lentos, fluidos o pausados en distintas trayectorias, desplazamientos y con acompañamiento musical.
• Explora, en colectivo, movimientos, gestos, formas, colores, sonidos y silencios, y acuerda una estructura creativa para crear un acontecimiento improvisado (flashmoob) en su escuela o en la comunidad, donde se invite a todas las personas a participar en el momento en que se está llevando a cabo.',21),
  ('6','Artes','Lenguajes','Combinación de la realidad y la ficción en elementos simbólicos de las manifestaciones culturales y artísticas, que dan identidad y sentido de pertenencia.','• Explora diversos elementos simbólicos que se encuentran en el entorno, a través del uso del color y las formas.
• Infiere la intención del autor o autora al utilizar los siguientes elementos: movimiento, gesto, forma, sonido y/o color en una manifestación cultural y artística, y compara sus ideas con las de sus pares.
• Reinterpreta una manifestación cultural o artística con un lenguaje artístico distinto al que se utilizó en su creación, para crear nuevas formas de simbolización.
• Aprecia y recrea una danza ritual colectiva, con elementos simbólicos propios de cada participante.',22),
  ('6','Artes','Lenguajes','Análisis y representación de guiones teatrales.','• Formula comentarios críticos respecto de un guion teatral de su elección, para expresar sus gustos, intereses e ideas, así como para desarrollar la argumentación.
• Realiza una representación teatral en colectivo, jugando con combinaciones de secuencias de sonidos y movimientos rápidos, lentos, agudos, graves, fuertes, débiles, pausas y con acentos variados.
• Emplea diversos elementos de los lenguajes artísticos, para crear escenografía, vestuario y maquillaje en la escenificación de una obra de teatro infantil o una situación improvisada a la que se invite a familiares y otros miembros de la comunidad como espectadores y espectadoras.',23),
  ('6','Literatura','Lenguajes','Lectura y análisis de mitos y leyendas, para su disfrute y valoración.','• Lee mitos y leyendas de México y del mundo, y reconoce las características y funciones de cada tipo de texto.
• Analiza mitos y leyendas de México y del mundo, y discute sobre su significado.
• Distingue las diferencias y similitudes entre los mitos y leyendas.
• Recupera mitos y leyendas con las personas de su comunidad y de libros, y las compila.
• Elabora un compendio de mitos y leyendas para compartir, que incluye título, portada, portadilla, introducción e índice.
• Representa un mito o leyenda de su interés mediante una escultura, cómic, performance, entre otros.',24),
  ('6','Ciencias Naturales','Saberes y Pensamiento Científico','Estructura y funcionamiento del cuerpo humano: sistemas circulatorio, respiratorio e inmunológico, y su relación con la salud ambiental, así como acciones para su cuidado.','• Explica la participación del sistema inmunológico en la defensa y protección del cuerpo humano ante infecciones y enfermedades, algunas de las células y órganos que lo conforman, sin profundizar en características y funciones específicas.
• Describe los beneficios y practica acciones para fortalecer y cuidar el sistema inmunológico: vacunación, higiene, alimentación saludable, consumo de agua simple potable, descanso, actividades físicas y recreativas.
• Argumenta la importancia de las vacunas como aportes científicos y tecnológicos para prevenir enfermedades transmisibles y de la Cartilla Nacional de Salud para dar seguimiento a su estado de salud, así como de prácticas culturales para prevenirlas.
• Explica los factores que ponen en riesgo la salud y aquellos que la favorecen al analizar diversas situaciones y propone acciones para reducir la propagación de enfermedades transmisibles en los entornos familiar, escolar y comunitario.',25),
  ('6','Ciencias Naturales','Saberes y Pensamiento Científico','Etapas del desarrollo humano: proceso de reproducción y prevención de infecciones de transmisión sexual (ITS) y embarazos en adolescentes, en el marco de la salud sexual y reproductiva.','• Analiza y argumenta las implicaciones y riesgos del embarazo a temprana edad o en adolescentes, y las consecuencias en los ámbitos de salud, personal, familiar, educativo, social y económico.
• Toma decisiones responsables e informadas relacionadas con la salud sexual y reproductiva, a partir de comprender que el
• ejercicio de la sexualidad es una decisión propia, en la que permean los valores, formas de pensar de cada persona y la cultura, y forma parte de los derechos sexuales.
• Compara y argumenta ventajas y desventajas de llevar a cabo conductas sexuales responsables para evitar embarazos e ITS, incluido el VIH: uso del condón, retraso de la actividad sexual o la abstención.
• Analiza creencias e ideas falsas en torno a las ITS, con base en las vías de transmisión y prevención, el uso de métodos anticonceptivos (variedad, efectividad y accesibilidad) y las conductas de autocuidado.
• Reconoce que el consumo de alcohol y otras sustancias adictivas, el rechazo al uso de métodos anticonceptivos, entre otros, son factores que propician conductas violentas vinculadas al ejercicio de la sexualidad: abuso sexual, hostigamiento, violación, violencia infantil y de género.',26),
  ('6','Ciencias Naturales','Saberes y Pensamiento Científico','Alimentación saludable: características de la dieta correcta, costumbres de la comunidad, riesgos del consumo de alimentos ultraprocesados, y acciones para mejorar la alimentación.','• Establece relaciones entre problemas asociados a la alimentación: sobrepeso, obesidad y desnutrición con factores de riesgo como consumo de alimentos y bebidas ultraprocesadas; analiza las causas y riesgos de trastornos de la alimentación como la anorexia y la bulimia.
• Analiza etiquetas de diversos productos que consume regularmente para conocer los ingredientes que los componen, así
• como su contenido y aporte nutrimental, y tomar decisiones a favor de una alimentación saludable.
• Propone platillos para el consumo familiar en los que incorpora alimentos regionales y de temporada que brinden una alimentación saludable a bajo costo.
• Propone y practica acciones para prevenir enfermedades no transmisibles como sobrepeso, obesidad y desnutrición, vinculadas con factores protectores como actividad física diaria, alimentación baja en azúcares, sal y grasas, además de beber agua simple potable.',27),
  ('6','Ciencias Naturales','Saberes y Pensamiento Científico','Funciones vitales que caracterizan a plantas y animales como seres vivos, y su relación con el entorno natural, así como sus cambios a través del tiempo.','• Indaga y explica cambios en los seres vivos y en el entorno natural a través del tiempo, a partir de reconocer causas y consecuencias de su extinción hace más de 10 000 años y en la actualidad, en México y el mundo.
• Comprende y explica la importancia de los fósiles como evidencia para la reconstrucción de la vida en el pasado, su relación con organismos y entornos actuales, y la evolución de los seres vivos; describe cómo se
• lleva a cabo el proceso de fosilización a partir de construir modelos.
• Propone y practica acciones para cuidar a los seres vivos actuales y prevenir su extinción.
• Comprende que las funciones vitales de nutrición, reproducción y relación con el entorno natural caracterizan a los seres vivos, incluido el ser humano.',28),
  ('6','Ciencias Naturales','Saberes y Pensamiento Científico','Factores que conforman la biodiversidad y el medio ambiente, la riqueza natural de México y su relevancia como parte del patrimonio biocultural de la humanidad, y la importancia de su conservación.','• Comprende que el medio ambiente es el conjunto de componentes naturales (factores biológicos: seres vivos, y factores físicos: agua, aire, suelo, Sol, clima, entre otros) en interacción con los componentes sociales (aspectos culturales, económicos, científicos, tecnológicos y políticos).
• Analiza situaciones que se relacionan con problemas medio ambientales de la comunidad y el impacto que tienen en la salud ambiental.
• Propone y practica acciones que favorecen el cuidado del medio ambiente; comprende el estrecho vínculo que tiene con el bienestar común, por lo que se requiere establecer una relación armónica con el medio ambiente.',29),
  ('6','Ciencias Naturales','Saberes y Pensamiento Científico','Pérdida de biodiversidad, problemas medio ambientales en la comunidad, México y el mundo, acciones orientadas a fortalecer estilos de vida sustentables.','• Analiza y explica algunos problemas medio ambientales de la comunidad, México y el mundo, sus causas y consecuencias en la salud ambiental.
• Comprende que el efecto invernadero es un proceso natural que favorece la vida en el planeta; establece relaciones entre su alteración, la contaminación del aire y el cambio climático, así como las consecuencias en el medio ambiente y la salud.
• Indaga y propone acciones orientadas a promover el consumo responsable en la escuela, familia y comunidad para favorecer estilos de vida sustentables y el bienestar común.
• Indaga proyectos de mejora del medio ambiente desarrollados por diversos pueblos, culturas, grupos y organizaciones de la sociedad civil, dependencias estatales o nacionales; y, reconoce el papel que desempeñan en la prevención y mitigación de diferentes problemáticas medio ambientales.',30),
  ('6','Física','Saberes y Pensamiento Científico','Costos y beneficios del consumo de agua, energía eléctrica y combustibles en la satisfacción de necesidades personales.','• Describe en qué actividades de la casa y la escuela, se utilizan recursos energéticos: energía eléctrica y diversos combustibles (madera, petróleo, carbón, gas), y analiza cómo impactan en el medio ambiente.
• Indaga y calcula el consumo de energía eléctrica, de gas o carbón que se utiliza en cada actividad; reconoce y practica acciones concretas para disminuir su consumo en casa y escuela.
• Analiza el costo ambiental que implica el uso de combustibles y energía eléctrica para tomar decisiones de consumo responsable en casa, escuela y comunidad, y disminuir el impacto en el medio ambiente.',31),
  ('6','Ciencias Naturales','Saberes y Pensamiento Científico','Propiedades de los materiales: dureza, flexibilidad y permeabilidad y su aplicación en la satisfacción de necesidades; caracterización de los gases con base en sus propiedades.','• Comprende que el aire es un gas, a partir de describir sus características: color, olor, sabor y si se puede comprimir, asir o introducir a un recipiente.
• Describe propiedades de los gases al contrastarlos con sólidos y líquidos, con base en el volumen -espacio que ocupan-, la compresibilidad -propiedad de reducir su volumen- y la fluidez -propiedad de ocupar todo el espacio del recipiente que los contiene-.
• Comprende que los gases, al igual que los líquidos y los sólidos, tienen masa a partir de medirla con ayuda de una balanza.
• Describe los cambios de volumen que presenta un gas a partir de experimentar con la variación de la temperatura; comprende que lo ocurrido es por la expansión del gas y no por el aumento de la cantidad de materia de este.',32),
  ('6','Ciencias Naturales','Saberes y Pensamiento Científico','Cambios permanentes en los materiales y sus implicaciones en la vida diaria.','• Explica la combustión y la oxidación de diferentes materiales como cambios permanentes, los factores que intervienen en ellos e identifica sus implicaciones en la vida diaria.
• Plantea y comprueba hipótesis relacionadas con la combustión, al experimentar con diversos materiales como madera o papel, y describir el cambio en sus propiedades, antes y después del proceso (trasformación de las propiedades originales).
• Identifica y describe la oxidación de materiales en su entorno, como la de los alimentos (manzanas, plátanos o aguacate), y de metales (hierro), así como, las sustancias o materiales que se utilizan para evitar la oxidación.
• Indaga y describe las implicaciones medio ambientales, económicas y sociales de los procesos de combustión y oxidación, y acciones que pueden realizarse para disminuir su efecto.',33),
  ('6','Física','Saberes y Pensamiento Científico','Efecto del magnetismo y de la fuerza de gravedad.','• Describe el efecto de la fuerza gravitacional sobre los cuerpos, a partir de experimentar con la caída y reposo de objetos, explica y representa con modelos los cambios ocurridos en la caída de objetos.
• Comprende que la masa es la cantidad de materia de un cuerpo, a diferencia del peso, que es la fuerza con la que la Tierra atrae dicho cuerpo por acción de la gravedad, a partir de
• actividades prácticas o simuladores que ejemplifiquen la caída de diversos objetos con masas iguales y diferentes, e identifica que el tiempo de caída es independiente de la masa.',34),
  ('6','Física','Saberes y Pensamiento Científico','Transformaciones de la energía térmica y eléctrica, así como su aplicación tecnológica.','• Comprende que la electricidad es una forma de energía que se caracteriza por el movimiento o acumulación de cargas eléctricas, y experimenta con las propiedades de conducción o aislamiento eléctrico, para identificar algunos materiales, como los metales que poseen conductividad eléctrica.
• Describe que hay dos tipos de cargas eléctricas, “positiva (+)” y “negativa (-)”, a partir de las cuales se determinan las interacciones entre los objetos; cuando dos objetos cargados eléctricamente se atraen, significa que sus cargas eléctricas son diferentes (+ -), y si se repelen significa que sus cargas eléctricas son iguales (++; --).
• Reconoce las propiedades que tienen los materiales para conducir la corriente eléctrica (conductores) y aquellos que no la conducen (aislantes), y los aplica en un circuito eléctrico; experimenta y describe interacciones de atracción y repulsión eléctrica (electricidad estática) de objetos.
• Reflexiona acerca del uso de la energía eléctrica para satisfacer necesidades y el impacto negativo en el medio ambiente que produce su generación y consumo.',35),
  ('6','Física','Saberes y Pensamiento Científico','Sistema Solar y Universo: características de sus componentes, y aportaciones culturales, científicas y tecnológicas que han favorecido su conocimiento.','• Describe características de forma, ubicación, tamaño, distancia, color y temperatura de algunos componentes del Universo: galaxias y estrellas.
• Describe las características principales de la Vía Láctea, y la reconoce como la galaxia en la que se ubica el Sistema Solar.
• Indaga, argumenta y valora la importancia de diversas aportaciones culturales, científicas y tecnológicas, entre ellas, los telescopios, satélites artificiales y sondas espaciales en la investigación y conocimiento del Universo.',36),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Estudio de los números. Expresa oralmente la sucesión numérica hasta seis cifras, en español y hasta donde sea posible, en su lengua materna, de manera ascendente y descendente a partir de un número natural dado.','• Expresa oralmente la sucesión numérica hasta billones, en español y hasta donde sea posible, en su lengua materna, de manera ascendente y descendente a partir de un número natural dado.
• Ordena, lee y escribe números naturales de más de nueve cifras e interpreta números decimales en diferentes contextos.
• Identifica semejanzas y diferencias entre el sistema de numeración decimal y otros sistemas como el maya y el romano.',37),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Suma y resta, su relación como operaciones inversas.','• A partir de situaciones problemáticas vinculadas a diferentes contextos, suma y resta números decimales y fracciones con diferentes denominadores.
• Utiliza, explica y comprueba sus estrategias para calcular mentalmente sumas y restas de dos números decimales hasta centésimos.',38),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Multiplicación y división, su relación como operaciones inversas.','• Resuelve situaciones problemáticas vinculadas a diferentes contextos que implican dividir números decimales entre naturales.
• Resuelve situaciones problemáticas vinculadas a diferentes contextos que implican dividir números fraccionarios entre números naturales.',39),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Relaciones de proporcionalidad. Resuelve situaciones problemáticas de proporcionalidad en las que determina valores faltantes de números naturales, a partir de diferentes estrategias (cálculo del valor unitario, de dobles, triples o mitades).','• A partir de situaciones problemáticas de proporcionalidad vinculadas a diferentes contextos, determina valores faltantes en las que en ocasiones se conoce el valor unitario y en otras no.
• Resuelve situaciones problemáticas vinculadas a diferentes contextos que implican comparar razones expresadas con dos números naturales y con una fracción.
• Utiliza, explica y comprueba sus estrategias para calcular mentalmente los porcentajes: 50%, 25%, 10% y 1%, de un número natural.
• Resuelve situaciones problemáticas vinculadas a diferentes contextos que implican calcular el tanto por ciento de una cantidad o el porcentaje que representa una cantidad de otra.',40),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Cuerpos geométricos y sus características.','• Explora y reconoce las características del cilindro y cono; anticipa y comprueba desarrollos planos que permiten construirlos.',41),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Figuras geométricas y sus características.','• Identifica y comprueba en diferentes objetos y dibujos con forma circular, la relación que existe entre la circunferencia y el diámetro (valor aproximado de π).
• Utiliza instrumentos geométricos para trazar polígonos regulares.',42),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Ubicación espacial. Elabora e interpreta croquis para comunicar la ubicación de seres vivos, objetos, trayectos o lugares.','• Lee, interpreta y elabora planos para comunicar la ubicación de seres vivos y objetos.
• Resuelve situaciones que requieren ubicar puntos en el primer cuadrante del plano cartesiano.',43),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Perímetro, área y noción de volumen.','• Resuelve situaciones problemáticas que implican calcular el perímetro y área de figuras compuestas por triángulos y cuadriláteros; utiliza unidades convencionales (m, cm, m² y cm²) para expresar sus resultados.
• Resuelve problemas que implican construir, estimar y comparar el volumen de cuerpos y prismas rectos rectangulares mediante el conteo de cubos, y reconoce que existen diferentes cuerpos con el mismo volumen.',45),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Organización e interpretación de datos.','• Interpreta información cuantitativa y cualitativa contenida en tablas, gráficas de barras y circulares para responder preguntas vinculadas a diferentes contextos; construye gráficas de barras.
• Genera y organiza datos, determina la moda, la media aritmética y el rango para responder preguntas vinculadas a diferentes contextos.',46),
  ('6','Matemáticas','Saberes y Pensamiento Científico','Nociones de probabilidad. Identifica situaciones de distintos contextos en las que interviene o no el azar; registra resultados de experiencias aleatorias en tablas de frecuencias y expresa la frecuencia absoluta y la relativa.','• Clasifica eventos de diversos contextos utilizando términos como seguro, imposible, probable, muy probable o poco probable que sucedan.
• A partir de distintas situaciones azarosas, determina los resultados posibles y los representa en tablas de doble entrada o en diagramas de árbol.',47),
  ('6','Geografía','Ética, Naturaleza y Sociedades','Valoración de la biodiversidad en el territorio donde se ubica la localidad, entidad, México y el mundo, valores y acciones sustentables.','• Comprende la biodiversidad en la Tierra, su sistema de relaciones e interdependencia global.
• Interpreta representaciones cartográficas de la riqueza en biodiversidad de continentes (África, América, Antártida, Asia, Europa, Oceanía), aguas oceánicas y continentales.
• Explica los procesos ecosistémicos de la biodiversidad, en relación con la circulación de energía, mediante las interacciones entre los seres humanos, otros seres vivos, el agua, el aire y el suelo, así como sus beneficios ambientales.
• Comprende relaciones sociales económicas, culturales y políticas en diversas interacciones mediadas por intereses (formas de producción, abastecimiento, distribución, estilos de consumo en el mundo, percepciones del entorno, tradiciones alimenticias, culturales, identidad cultural, sentido de pertenencia, inspiración estética o espiritual), así como formas de concebir la naturaleza, que favorecen relaciones armónicas o desfavorecen su integridad y su función para la vida incidiendo en el desbalance de la biósfera como lo evidencia el cambio climático.
• Analiza críticamente formas de cuidar, respetar y proteger la biodiversidad sustentablemente.',49),
  ('6','Geografía','Ética, Naturaleza y Sociedades','Valoración de la megadiversidad mexicana: megadiversidad en México, diversidad cultural, relaciones ser humano-naturaleza y representaciones distintas de las diferentes culturas o grupos sociales, sobre la biodiversidad y su manejo, acorde a sus contextos.','• Investiga sobre las características geográficas y las regiones biogeográficas que hacen de México un país megadiverso y biocultural, relacionándolas con las zonas climáticas, los espacios económicos, la distribución de la población en México y los países con mayor biodiversidad.
• Analiza y argumenta cómo la biodiversidad local influye en las tradiciones culturales de la comunidad (cultivos, alimentos, indumentaria, herbolaria, fiestas, ritos, entre otras).
• Argumenta por qué la megadiversidad de México es parte de su patrimonio biocultural, para comprender su estrecha vinculación con el desarrollo social, la salud y el bienestar de la población, y ejemplifica elementos del patrimonio biocultural de México reconocidos a nivel mundial.',50),
  ('6','Geografía','Ética, Naturaleza y Sociedades','Sustentabilidad de la biodiversidad y humanismo: rasgos de los estilos de vida y modelos de desarrollo dominantes y su impacto en la biodiversidad, implicaciones socioambientales de la preservación.','• Valora las causas y los factores sociales que impactan en la problemática ambiental, en la salud de los ecosistemas, en los seres humanos y demás seres vivos, entre otros riesgos que amenazan la continuidad de la vida en la Tierra.
• Analiza críticamente las implicaciones socioambientales de la mercantilización de la biodiversidad, y propone alternativas sustentables para favorecer la estabilidad y seguridad de la convivencia humana con la naturaleza.
• Propone y realiza acciones de consumo sustentable en su casa, escuela y comunidad para proteger y contribuir a regenerar y preservar la biodiversidad.
• Dialoga acerca de qué manera, los posibles efectos del cambio climático pueden afectar a la biodiversidad y a las personas de acuerdo con el género y la edad o si viven en zona urbana o rural.',51),
  ('6','Geografía','Ética, Naturaleza y Sociedades','Ética y biodiversidad: factores sociales que propician la convivencia armónica con el medio ambiente basada en el respeto, responsabilidad, justicia social y equidad con la naturaleza.','• Valorar la importancia del respeto y la colaboración en el cuidado y aprovechamiento sustentable de la biodiversidad, considerándola como parte imprescindible para la vida humana, y cuya protección debe promover la justicia social, desde la equidad y la solidaridad.
• Indaga y evalúa situaciones que impactan la biodiversidad de México, considerando los valores, las interacciones y acciones personales, familiares, comunitarias y de otras sociedades.
• Propone y pone en práctica, de manera crítica, con juicio ético y de acuerdo con sus posibilidades, acciones de bienestar común para la regeneración y preservación de la biodiversidad en la vida cotidiana; reflexionando acerca de los derechos de la naturaleza.
• Argumenta sobre la responsabilidad de todos los
• sectores sociales, para llevar a cabo medidas necesarias y solidarias que protejan a la megadiversidad del país y del mundo, bajo un enfoque ético y comprometido con la sustentabilidad, para garantizar su regeneración, preservación, el bienestar común y el derecho humano a un ambiente sano de las presentes y futuras generaciones.',52),
  ('6','Geografía','Ética, Naturaleza y Sociedades','Derechos humanos: a un ambiente sano y acceso al agua potable.','• Indaga, comprende y dialoga sobre la importancia del agua y su balance con otros elementos del ecosistema global, para garantizar la supervivencia de la biodiversidad, incluido el ser humano.
• Comprende que la Constitución Política de los Estados Unidos Mexicanos, las leyes nacionales y los tratados internacionales suscritos por México, garantizan los derechos a la salud, a un medio ambiente sano, y el acceso a agua potable.
• Dialoga y argumenta acerca de cómo ejerce sus derechos humanos a la salud, al agua potable y a un ambiente sano y adecuado para su desarrollo y bienestar, y se compromete a respetar la biodiversidad, actuar con reciprocidad, cuidándola y contribuyendo en su regeneración y preservación.',53),
  ('6','Geografía','Ética, Naturaleza y Sociedades','La responsabilidad compartida, el respeto y el consumo sustentable: acciones colectivas a favor de la protección, regeneración y preservación de la biodiversidad y el bienestar socioambiental.','• Investiga acciones de consumo sustentable del agua y la biodiversidad, para contribuir a mitigar el impacto negativo de la sociedad en estos sistemas de la naturaleza.',54),
  ('6','Geografía','Ética, Naturaleza y Sociedades','Riesgos de desastre y crisis humanitarias, asociados a fenómenos naturales y generados por acciones humanas: sus causas y consecuencias, para contribuir, de manera solidaria, a minimizar sus efectos.','• Investiga en noticias, lecturas o narraciones, desastres ocurridos en México y otros países del mundo.
• Indaga sobre riesgos de desastre en el territorio nacional, asociados a fenómenos naturales, los representa de manera cartográfica y localiza las zonas de seguridad.
• Investiga, en distintas fuentes, acerca de las crisis humanitarias actuales, causadas por desastres de tipo natural o antrópico, y que generan desplazamiento de grandes grupos de personas, considerando las razones por las que tuvieron que desplazarse de esa región, ¿a qué lugar llegaron a refugiarse?, ¿cuáles son las situaciones de peligro que enfrentan en su camino?, ¿por qué se les considera refugiados?; y a ¿quién le corresponde proporcionarles ayuda?
• Dialoga acerca de cómo se sienten las personas al ser obligadas a abandonar su lugar de origen, dejando atrás
• su patrimonio y su forma de vida, ¿qué pasa con las familias?, ¿cómo viven niñas, niños y adolescentes?, y ¿cómo afecta esta situación a las mujeres y personas con discapacidad?
• Identifica los mecanismos de prevención que se utilizan en México y otros países, tales como la alerta sísmica, la alerta temprana para ciclones, la alerta temprana para tsunamis, el monitoreo de volcanes, entre otros, que permiten mitigar el impacto económico y social derivado de dichas eventualidades.
• Indaga acerca de los organismos internacionales que proporcionan ayuda humanitaria, así como cuáles son sus funciones y qué tipo de ayuda proporciona.
• Comprende que las crisis humanitarias precisan de la colaboración de otros países, aportando ayuda humanitaria.
• Propone acciones que pueden llevar a cabo las personas o comunidades, para minimizar los efectos de las crisis humanitarias en su entidad, país o en otra parte del mundo.',55),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Construcción de la cultura de paz: análisis de conflictos vecinales y/o territoriales del pasado y del presente entre personas, grupos, comunidades y pueblos para identificar sus causas, cómo se desarrollaron y cómo se resolvieron, destacando el diálogo, la negociación y la tolerancia.','• Analiza críticamente algunos ejemplos de conflictos territoriales en México en el pasado o el presente vinculados con la disposición, obtención, despojo de recursos, diferencias económicas, políticas, culturales, indefinición de límites territoriales, para valorar las relaciones de justicia, respeto, colaboración, reciprocidad y convivencia armónica, que deben existir entre las personas y países para promover la cultura de paz.
• Indaga en fuentes bibliográficas, hemerográficas o en narraciones orales, cómo se desarrolló el conflicto, así como los recursos que se usaron para abordarlo.
• Realiza propuestas para promover la cultura de paz en distintos ámbitos de convivencia.',56),
  ('6','Historia','Ética, Naturaleza y Sociedades','La democracia como forma de gobierno en México y su construcción a través de la historia.','• Analiza críticamente las transformaciones en la forma de gobierno en México durante el siglo XX: el fin del porfiriato, la Revolución Mexicana y la promulgación de la Constitución de 1917, que reafirma el sistema federal, la separación y equilibrio de Poderes; las posteriores reformas legales que garantizan la participación política equitativa e igualitaria, tales como la reforma constitucional de 1953 que reconoce el derecho al voto de las mujeres.
• Identifica cómo se retomaron las demandas históricas y los conflictos en la construcción de la República representativa,
• democrática, laica, federal, pluricultural y plurilingüe, que hoy nos rige como país.
• Indaga y analiza críticamente algunas experiencias de organización de pueblos originarios, afromexicanos y migrantes, así como otros pueblos y colectivos que dan cuenta de la toma de decisiones conjuntas, para el ejercicio de la autoridad y la corresponsabilidad en la búsqueda del bienestar común.',57),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Cultura democrática: principios éticos que subyacen en los acuerdos, normas y leyes democráticas, importancia de su cumplimiento y evaluación de su aplicación justa, equitativa e igualitaria en la vida cotidiana.','• Evalúa la aplicación justa, equitativa e igualitaria de acuerdos, normas y leyes en situaciones cotidianas del ámbito local o nacional, comprende que esto favorece la cultura democrática.
• Argumenta en favor del cumplimiento de los principios de igualdad, respeto, inclusión, responsabilidad, libertad, justicia, legalidad, honestidad, interculturalidad, entre otros, y analiza, de forma crítica, los beneficios de llevarlos a cabo, en los ámbitos personal y colectivo, así como en la interrelación de la sociedad.',58),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Desafíos para la construcción de sociedades inclusivas y equitativas: la violencia de género como un problema estructural, con un peso social, cultural e histórico, a fin de visibilizar sus causas y consecuencias, para erradicarlas,','• Analiza críticamente las causas y consecuencias de la violencia de género en México y el mundo, como un problema estructural, social, cultural e histórico.
• Identifica cómo se naturaliza la desigualdad de género, lo que contribuye a su reproducción.
• Identifica algunas formas en las que está presente la desigualdad',59),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','buscando la equidad como derecho.','• en las relaciones de pares, en la escuela y la comunidad; por ejemplo, en los juegos, en los deportes, en las TIC’S, entre otras, y propone cómo transformarlas en nuevas formas de relación, que favorezcan la equidad, respeten y aprecien la diversidad.',60),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Contribuciones al bienestar colectivo: servicios públicos e infraestructura para satisfacer las necesidades de salud, educación, esparcimiento, comunicación, seguridad y justicia de las personas que habitan la comunidad y el país, así como la rendición de cuentas y el uso transparente de los recursos como parte de una sociedad democrática.','• Analiza los servicios públicos y la infraestructura que benefician a las personas de su comunidad y del país, e identifica cómo es posible contribuir en su mantenimiento y cuidado, con un manejo transparente de los recursos, desde los ámbitos de la sociedad, como el pago de impuestos, trabajo comunitario, tequio, entre otros.
• Comprende qué es la rendición de cuentas y la transparencia en el manejo de los recursos públicos, por qué es importante que los ciudadanos la demanden a sus gobernantes y cómo pueden hacerlo.',61),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','El derecho a la protección de la integridad física y mental, ante cualquier forma de maltrato, abuso o explotación de tipo sexual o laboral, así como, la identificación de personas e instituciones que pueden apoyar para el ejercicio de ese derecho.','• Ejerce el derecho a la protección de la dignidad, integridad y los datos personales contra cualquier forma de maltrato, abuso o explotación de tipo sexual o laboral, de manera presencial o a través de medios electrónicos, en los distintos ámbitos de convivencia (familia, escuela y comunidad).
• Identifica Instituciones que brindan protección a niñas, niños y adolescentes ante situaciones de maltrato, abuso o
• explotación de tipo sexual y laboral y propone acciones de defensa y protección a los derechos de todas las personas.',62),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','La lucha por el reconocimiento de los derechos humanos: la protección de la dignidad de todas las personas y grupos sociales para vivir con gozo y armonía, sin importar las diferencias.','• Comprende que los logros de las luchas históricas por el reconocimiento a los derechos humanos se han plasmado en la constitución y los tratados internacionales.
• Reconoce que los derechos humanos son universales, indivisibles, interdependientes, progresivos, inalienables, irrenunciables.
• Dialoga acerca de que las leyes y los tratados internacionales son instrumentos que podemos utilizar para la demanda y ejercicio de los derechos humanos.
• Investiga sobre grupos y organizaciones, que en la actualidad luchan por el reconocimiento de sus derechos y por la justicia social.
• Dialoga acerca de por qué los derechos a la memoria colectiva, la verdad y la justicia son importantes contra la impunidad y la no repetición de actos que violentan la dignidad y los derechos humanos.',63),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Cumplimiento de los derechos humanos: estudio de casos de actos de discriminación, racismo o violencias que suceden','• Analiza críticamente un caso de racismo, discriminación o violencias en el continente americano o en otros países del mundo, e identifica las causas y las consecuencias culturales, económicas, políticas y sociales',64),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','actualmente en México y el mundo.','• que derivan del caso analizado, y propone acciones solidarias que favorezcan el respeto y el cumplimiento de los derechos humanos.',65),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Valores y prácticas de los pueblos originarios y afromexicanos: el respeto, la reciprocidad y el beneficio mutuo como valores fundamentales de la relación con la naturaleza y con otras personas.','• Indaga acerca de experiencias de convivencia en algunos pueblos originarios, afromexicanos o grupos urbanos de México y del Continente Americano, que se sustentan en respeto, la reciprocidad y el beneficio mutuo, en la relación armónica con la naturaleza, y con otros seres humanos.
• Reconoce que su convivencia se sustenta en el trabajo colectivo, la reciprocidad, el aprovechamiento sustentable de la naturaleza en el territorio, la búsqueda del beneficio mutuo, y valora los beneficios que ello implica, para practicar el buen vivir.',66),
  ('6','Formación Cívica y Ética','Ética, Naturaleza y Sociedades','Pueblos y culturas de América y el mundo: el respeto a las costumbres, tradiciones y formas de vivir de diferentes culturas.','• Indaga algunos momentos en los que las culturas del mundo han interactuado, producto de las migraciones, de la búsqueda e intercambio de productos y materiales, de las relaciones comerciales, así como de la exploración y la expansión territorial.
• Reconoce que las culturas actuales en diferentes partes del mundo se han formado a través del tiempo y tienen distintos orígenes.
• Valora semejanzas y diferencias como parte de la diversidad humana y su riqueza cultural.
• Localiza y describe las características (zonas climáticas, relieve y aguas continentales) de algunos pueblos y culturas de los continentes: África, América, Antártida, Asia, Europa y Oceanía, así como sus relaciones y formas de vida.
• Reconoce algunos efectos globales en la vida cotidiana de pueblos, comunidades y países que se encuentran distantes del lugar donde se originan las situaciones de afectación socioambiental, y sus derivaciones económicas, políticas, sociales, culturales, ecológicas, entre otras.
• Identifica puntos y líneas imaginarias del planeta Tierra, y localiza lugares en México y el mundo, utilizando las coordenadas geográficas.',67),
  ('6','Historia','Ética, Naturaleza y Sociedades','Movimientos sociales en el México de los siglos XIX y XX: la Independencia y la Revolución Mexicana.','• Indaga en fuentes bibliográficas, hemerográficas y digitales, así como en fotografías y objetos, las principales características sociales, económicas, políticas y culturales del Porfiriato.
• Indaga acerca de las causas que dieron origen al movimiento revolucionario de 1910, como las injusticias, entre las que se encuentran: el despojo de las tierras comunales de campesinos y pueblos originarios, la explotación laboral por las compañías extranjeras, casos como las huelgas de los trabajadores de Cananea, Sonora (1906) y de Río Blanco,
• Veracruz (1907), y la apropiación y control de diversas extensiones de tierras, bosques y aguas en pocas manos.
• Indaga sobre procesos y luchas por la justicia, que ocurren actualmente en diversas partes del país.
• Investiga sobre la participación de distintos grupos en la búsqueda por la justicia social, el reconocimiento y la garantía de los derechos sociales, además de cómo estos ideales se plasmaron en la Constitución Política de los Estados Unidos Mexicanos de 1917.
• Investiga en fuentes bibliográficas, hemerográficas e iconográficas, sobre los debates del constituyente de 1917, para lograr el reconocimiento y la garantía de los derechos sociales.
• Analiza los artículos 3o., 27 y 123 de la Constitución Política de los Estados Unidos Mexicanos referentes a la educación, la propiedad de las tierras y el trabajo, indaga los debates que se dieron en el constituyente para su reconocimiento y garantía.
• Investiga el impacto que tuvo en la entidad el movimiento revolucionario.
• Analiza la participación en el movimiento revolucionario de personajes como Francisco I. Madero, Emiliano Zapata, Francisco Villa, Venustiano Carranza, entre otros, destacando sus
• ideales, así como su origen social y cultural.
• Reconoce la participación de las mujeres en la lucha revolucionaria, tales como María de la Luz Espinoza Barrera, Carmen Vélez “La Generala”, María Quinteras de Meras, Petra Herrera, las “adelitas”, entre otras.
• Destaca y compara la participación actual de mujeres mexicanas entre las que se identifican indígenas y afromexicanas, en diversos ámbitos de la vida política, social y cultural del país.
• Representa en mapas, los lugares estratégicos y emblemáticos de la lucha por la Revolución Mexicana, y las rutas seguidas por los personajes que encabezaron este movimiento.',68),
  ('6','Historia','Ética, Naturaleza y Sociedades','México posrevolucionario (1917-1940): la vida cotidiana, los procesos que implicaron la reconfiguración del país en los ámbitos social, económico, político, religioso y cultural, así como el impacto en el ambiente.','• Indaga en fuentes bibliográficas, hemerográficas, iconográficas, objetos y construcciones acerca de la vida cotidiana en el México posrevolucionario, qué estragos dejó la guerra en las familias, comunidades y pueblos, cómo se modificó la vida cotidiana después de la lucha armada del movimiento de revolución, cómo cambiaron los pueblos y ciudades donde vivían, cuáles eran los principales trabajos y oficios, cómo era la educación de niñas y niños y qué es la escuela rural mexicana, cómo se divertían las personas, cuáles eran las expresiones culturales y artísticas, entre otros aspectos.
• Indaga acerca de cómo se vivió el movimiento revolucionario en diferentes regiones del país.
• Indaga en fuentes bibliográficas, hemerográficas y digitales, así como en fotografías y objetos, las características sociales, económicas, políticas, religiosas y culturales en el México posrevolucionario (1917-1940).
• Analiza el proceso que implicó la reconfiguración del país, tras la lucha revolucionaria, para la cimentación de un régimen político democrático, acorde con lo plasmado en la Constitución de 1917.
• Identifica las tensiones y conflictos entre caudillos revolucionarios y grupos políticos con diferentes intereses e ideologías, del periodo posrevolucionario.
• Analiza el proceso denominado Maximato (1928-1934), en la búsqueda de la estabilidad política que requería la República.
• Indaga las causas, desarrollo y consecuencias de la rebelión cristera, e identifica cómo se dio la negociación del conflicto que reafirmó la libertad de creencias y el estado laico.
• Representa en mapas, los lugares y zonas de confrontación de la lucha cristera.
• Identifica algunas acciones que se impulsaron durante el Cardenismo, como la expropiación petrolera y el reparto agrario a campesinos y comunidades indígenas.
• Dialoga acerca de cómo los procesos históricos han cambiado la vida de las personas y sus comunidades.',70),
  ('6','Geografía','Ética, Naturaleza y Sociedades','Migración y derechos humanos: migración interna y externa, causas y consecuencias sociales, económicas, culturales, políticas y ambientales.','• Reconoce los flujos migratorios en los que hay mayor cantidad de emigrantes en el mundo, identificando países de origen y de destino.
• Explica causas y consecuencias sociales, culturales, económicas, políticas y ambientales de la migración, en casos específicos en el mundo, mediante el análisis de noticias, documentales y algunos testimonios de migrantes internacionales.
• Ubica en mapas, las rutas que siguen los migrantes, desde su lugar de origen, hasta su destino.
• Reflexiona acerca de los impactos de las migraciones en la identidad y pertenencia de las personas, así como, los prejuicios que generan aspectos como la discriminación.
• Dialoga acerca de cómo cada país establece sus reglas para reconocer y otorgar la ciudadanía, así como las acciones que se podrían implementar para la protección de los derechos de las personas migrantes.
• Dialoga y elabora juicios éticos acerca de los derechos de las personas migrantes.',71),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Las familias como espacio para el desarrollo del sentido de pertenencia y autonomía, para una sana convivencia.','• Diseña e interactúa en distintos escenarios de convivencia, para fortalecer su autonomía y su participación en la familia.
• Promueve los valores familiares, para la resolución de conflictos y el desarrollo personal.',73),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Alternativas ante conflictos y problemas de la vida en la comunidad.','• Reflexiona y comparte los problemas y conflictos que se presentan en su comunidad, para proponer alternativas de solución viables.
• Valora propuestas de alternativas que plantea para valorar su viabilidad en su comunidad.',74),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','La escuela como ventana hacia el futuro.','• Indaga sobre experiencias de estudio y comunidades de práctica, para ampliar sus horizontes de formación.
• Se informa acerca de la oferta educativa en su región, para identificar sus posibilidades de ingreso al nivel de educación media.',75),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','La comunidad, como espacio para el aprendizaje y el bienestar común.','• Profundiza acerca de ideas, conocimientos y prácticas culturales, para proponer alternativas orientadas a promover, preservar y difundir para el bien común.
• Diseña, bajo los principios de respeto, y tolerancia, estrategias de organización ante diferentes situaciones, para la prevención de conflictos, la satisfacción de necesidades comunes y el desarrollo sustentable de su comunidad.',76),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Formas de ser, pensar, actuar y relacionarse.','• Valora sus experiencias acerca de las formas de ser, pensar, actuar y relacionarse en determinadas situaciones, para favorecer su comprensión, el ejercicio de la empatía y el logro de metas.',77),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Construcción del proyecto de vida. Replantea las formas de satisfacer las necesidades e intereses, para promover la autodeterminación orientada al cumplimiento de metas.','• Valora sus logros y retos afrontados en la historia personal para definir aspiraciones y acciones a realizar ante nuevas etapas de la vida.
• Valora logros y cambios en gustos, necesidades, intereses y habilidades actuales, para reestructurar metas que favorezcan el desarrollo personal y social.',78),
  ('6','Desarrollo personal','De lo Humano y lo Comunitario','Educación Integral en Sexualidad. Intercambia experiencias acerca de sensaciones de placer o displacer que se presentan en la interacción, para argumentar las causas, prever situaciones de riesgo y realizar prácticas seguras.','• Reflexiona acerca de la importancia de expresar su consentimiento o rechazo ante situaciones que le generan placeres y displaceres para valorar las implicaciones en su bienestar.',79),
  ('6','Desarrollo personal','De lo Humano y lo Comunitario','Equidad de género. Reflexiona sobre situaciones asociadas con la diversidad de identidades y género, para proponer acciones en contra de la discriminación.','• Analiza situaciones de discriminación asociadas con la identidad o género en la escuela, la comunidad y otros ámbitos, para reconocer formas de violencia y participar en acciones de prevención.',80),
  ('6','Educación Física','De lo Humano y lo Comunitario','Capacidades, habilidades y destrezas motrices.','• Aplica sus capacidades, habilidades y destrezas motrices al organizar y participar en situaciones de juego e iniciación deportiva, para favorecer su disponibilidad corporal.',81),
  ('6','Educación Física','De lo Humano y lo Comunitario','Potencialidades cognitivas, expresivas, motrices, creativas y de relación.','• Diseña propuestas de actividades lúdicas y expresivas a partir de sus intereses, capacidades y habilidades, para fortalecer su imagen corporal.',82),
  ('6','Educación Física','De lo Humano y lo Comunitario','Estilos de vida activos y saludables. Plantea alternativas de actividades físicas que puede practicar dentro y fuera de la escuela, con la intención de desarrollar un estilo de vida activo.','• Evalúa los factores que limitan la práctica constante de actividades físicas, para implementar opciones que permitan superarlos a lo largo de la vida.',83),
  ('6','Educación Física','De lo Humano y lo Comunitario','Pensamiento lúdico, estratégico y creativo.','• Emplea el pensamiento estratégico y divergente ante situaciones de juego o cotidianas, para valorar la actuación, individual y colectiva, y adaptarla de acuerdo con el contexto.',84),
  ('6','Educación Física','De lo Humano y lo Comunitario','Interacción motriz. Promueve ambientes de participación en situaciones de juego, iniciación deportiva y cotidianas, para valorar posibles interacciones en favor de una sana convivencia.','• Organiza e implementa situaciones de juego e iniciación deportiva, para favorecer la convivencia en la escuela y la comunidad.',85),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Acciones individuales que repercuten en la conservación y mejora de la salud.','• Promueve alternativas de hábitos de higiene personal y limpieza de los espacios en la comunidad, para impulsar la toma de decisiones informadas que contribuyan a asumir prácticas saludables y sostenibles.
• Comprende los riesgos del consumo de alimentos procesados y ultraprocesados en la salud y el medio ambiente, para favorecer la adopción de prácticas alimentarias saludables y sostenibles.
• Diseña alternativas que contribuyen a afrontar cambios o situaciones de riesgo relacionadas con accidentes, adicciones y formas de violencia, para valorar su pertinencia y determinar su viabilidad.',86),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Sentido de comunidad y satisfacción de necesidades humanas.','• Diseña alternativas orientadas a promover, preservar y, en caso necesario, replantear ideas, conocimientos y prácticas culturales, para impulsar una mayor difusión y participación.
• Diseña de manera consensuada, estrategias de organización ante diferentes situaciones que impliquen cambios que pueden generar resistencia, para la prevención de problemas y satisfacción de necesidades, así como el aprovechamiento responsable y sostenible de recursos.',87),
  ('6','Desarrollo personal y comunitario','De lo Humano y lo Comunitario','Toma de decisiones y creatividad, ante problemas de la vida.','• Describe los problemas de vida que ha enfrentado para reflexionar sobre su resolución con base en el juicio crítico.
• Valora su capacidad creadora para la solución de problemas en la vida y en su comunidad con base en el juicio crítico.
• Evalúa la asertividad para expresar sus emociones sin perjudicar a otra persona.
• Dramatiza una propuesta de juicio crítico en la de toma de decisiones para discernir la solución de los problemas de la vida.',88),
  ('6','Desarrollo personal','De lo Humano y lo Comunitario','Los afectos y su influencia en el bienestar.','• Reflexiona sobre hábitos que afectan positiva o negativamente en el estado de ánimo para lograr el bienestar personal y social.
• Crea estrategias que ayudan a la expresión adecuada de las emociones, y que favorecen la interacción y el bienestar personal y social.',89);
